input int    TP1_ClosePct       = 40;     // % del lote a cerrar en TP1
input int    TP2_ClosePct       = 40;     // % del lote a cerrar en TP2

input group "=== BREAKEVEN ==="
input double BE_BufferPct       = 20.0;   // BE como % del SL (20% → BE cuando precio = entry + 0.20×SL)

input group "=== FILTROS ==="
input bool   FilterMonday       = true;   // true = OPERA el lunes
input bool   FilterTuesday      = true;
input bool   FilterWednesday    = true;
input bool   FilterThursday     = true;
input bool   FilterFriday       = true;
input double MinSL_Points       = 1.00;   // SL mínimo (puntos reales = precio raw) ← CALIBRAR
input double MaxSL_Points       = 5.00;   // SL máximo (puntos reales = precio raw) ← CALIBRAR
input bool   ConfirmOnClose     = true;   // SIEMPRE true — NO optimizar

input group "=== LOGGING ==="
input bool   EnableCSV          = true;

input group "=== VISUAL ==="
input bool   VIS_Enable         = true;

input group "=== CONFIG ==="
input int    MagicNumber        = 202402; // Único para XAUUSD

//==================================================================
// GLOBALES
//==================================================================

CTrade trade;

// Specs del símbolo (cargadas en OnInit)
double g_tickValue;
double g_tickSize;
double g_valuePerPoint;
double g_volumeMin;
double g_volumeMax;
double g_volumeStep;
int    g_digits;

// Estado diario
double   g_rangeHigh       = 0;
double   g_rangeLow        = 0;
double   g_slDistance      = 0;
double   g_cachedLots      = 0;
bool     g_rangeCalculated = false;   // Se intentó calcular (evita recalcular en cada tick)
bool     g_rangeSet        = false;   // Rango válido y dentro de filtros
bool     g_tradeExecuted   = false;
bool     g_be_activated    = false;
bool     g_tp1_hit         = false;
bool     g_tp2_hit         = false;
datetime g_lastDay         = 0;

// Estado ConfirmOnClose
bool     g_breakoutPending = false;
string   g_pendingDir      = "";
datetime g_pendingBarTime  = 0;

// Niveles del trade activo
double   g_entryPrice      = 0;
double   g_slLevel         = 0;
double   g_tpLevel1        = 0;
double   g_tpLevel2        = 0;
double   g_tpLevel3        = 0;
double   g_beLevel         = 0;
string   g_tradeDir        = "";
datetime g_tradeTime       = 0;

// CSV
int      g_csvHandle       = INVALID_HANDLE;

//==================================================================
// OnInit
//==================================================================
int OnInit()
{
   // --- Cargar specs del símbolo dinámicamente
   g_tickValue    = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   g_tickSize     = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   g_volumeMin    = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   g_volumeMax    = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   g_volumeStep   = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   g_digits       = (int)SymbolInfoInteger(_Symbol, SYMBOL_DIGITS);

   if(g_tickSize <= 0) {
      Print("CRITICAL ERROR: TickSize = 0. Verifique el símbolo.");
      return INIT_FAILED;
   }

   g_valuePerPoint = g_tickValue / g_tickSize;

   // --- Diagnóstico completo (comparar contra valores esperados)
   Print("╔══════════════════════════════════════════════════╗");
   Print("║  BreakoutNY v8.01 — XAUUSD — FundingPips        ║");
   Print("╚══════════════════════════════════════════════════╝");
   Print("── Symbol Specs ───────────────────────────────────");
   Print("  Símbolo       : ", _Symbol);
   Print("  TickValue     : ", g_tickValue,    "  (esperado: 1.00)");
   Print("  TickSize      : ", g_tickSize,     "  (esperado: 0.01)");
   Print("  ValuePerPoint : ", g_valuePerPoint,"  (esperado: 100.0)");
   Print("  _Point        : ", SymbolInfoDouble(_Symbol, SYMBOL_POINT), "  (esperado: 0.01)");
   Print("  VolumeMin     : ", g_volumeMin,    "  (esperado: 0.01)");
   Print("  VolumeMax     : ", g_volumeMax,    "  (esperado: 5.00)");
   Print("  VolumeStep    : ", g_volumeStep,   "  (esperado: 0.01)");
   Print("── Config ─────────────────────────────────────────");
   Print("  ServerOffset  : UTC+", ServerOffsetHours);
   Print("  RiskAmountUSD : $", RiskAmountUSD);
   Print("  MinSL_Points  : ", MinSL_Points, "  ← PROVISIONAL (ejecutar calibrador)");
   Print("  MaxSL_Points  : ", MaxSL_Points, "  ← PROVISIONAL (ejecutar calibrador)");
   Print("  ConfirmOnClose: ", ConfirmOnClose);
   Print("── Lot Calc Example (slDist=2.50) ─────────────────");
   Print("  lotsRaw = ", RiskAmountUSD, " / (2.50 × ", g_valuePerPoint, ") = ",
         NormalizeDouble(RiskAmountUSD / (2.50 * g_valuePerPoint), 4));
   Print("───────────────────────────────────────────────────");

   // Advertencia si valuePerPoint no es ~100
   if(MathAbs(g_valuePerPoint - 100.0) > 5.0) {
      Print("⚠ WARNING: ValuePerPoint=", g_valuePerPoint,
            " difiere del esperado (100.0). Verifique specs del broker.");
   }

   // --- Configurar CTrade
   trade.SetExpertMagicNumber(MagicNumber);
   trade.SetDeviationInPoints(30);
   trade.SetTypeFilling(ORDER_FILLING_IOC);

   // --- Inicializar CSV
   if(EnableCSV) {
      g_csvHandle = FileOpen("BreakoutNY_XAUUSD_Trades.csv",
                              FILE_WRITE | FILE_CSV | FILE_ANSI | FILE_SHARE_READ, ",");
      if(g_csvHandle != INVALID_HANDLE) {
         FileWrite(g_csvHandle,
            "Date","Time","Weekday","Direction","EntryPrice",
            "SL_Pts","ExitType","ClosePrice","PnL_USD",
            "RangeHigh","RangeLow","SL_Final","BE_Activated","ConfirmOnClose");
         FileFlush(g_csvHandle);
         Print("CSV inicializado: BreakoutNY_XAUUSD_Trades.csv");
      } else {
         Print("WARNING: No se pudo crear el CSV.");
      }
   }

   return INIT_SUCCEEDED;
}

//==================================================================
// OnDeinit
//==================================================================
void OnDeinit(const int reason)
{
   if(g_csvHandle != INVALID_HANDLE) {
      FileFlush(g_csvHandle);
      FileClose(g_csvHandle);
   }
   if(VIS_Enable) VIS_CleanAll();
}

//==================================================================
// OnTick
//==================================================================
void OnTick()
{
   // ── Reset diario ─────────────────────────────────────────────
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   datetime today = (datetime)(
      StringToTime(StringFormat("%04d.%02d.%02d", dt.year, dt.mon, dt.day))
   );
   if(today != g_lastDay) {
      DailyReset();
      g_lastDay = today;
   }

   // ── Filtro de día ─────────────────────────────────────────────
   if(!IsTradingDayAllowed()) return;

   // ── Tiempos en hora servidor ──────────────────────────────────
   MqlDateTime sdt;
   TimeToStruct(TimeCurrent(), sdt);
   int sHour = sdt.hour;
   int sMin  = sdt.min;

   // Conversión UTC → Servidor
   // Range calc : 14:50 UTC → (14+offset):50 servidor
   // Window end : 15:XX  UTC → (15+offset):XX servidor
   // Force close: 17:00  UTC → (17+offset):00 servidor
   int rHour = 14 + ServerOffsetHours;   // 16 (UTC+2)
   int rMin  = 50;
   int wHour = 15 + ServerOffsetHours;   // 17 (UTC+2)
   int wMin  = EntryWindowEnd_Min;       // 15 → ventana hasta 17:15 servidor
   int fHour = 17 + ServerOffsetHours;   // 19 (UTC+2)

   // ── PASO 1: Calcular rango exactamente a las 14:50 UTC ────────
   if(!g_rangeCalculated && sHour == rHour && sMin == rMin) {
      CalculateRange();
      g_rangeCalculated = true;   // No recalcular durante este minuto
   }

   if(!g_rangeSet) return;

   // ── Cierre forzoso 17:00 UTC ──────────────────────────────────
   if(sHour >= fHour) {
      if(HasOpenPosition()) {
         CloseAllPositions("SessionEnd");
      }
      return;
   }

   // ── Ventana de entrada ────────────────────────────────────────
   bool afterRangeCalc = (sHour > rHour) || (sHour == rHour && sMin >= rMin);
   bool beforeWindowEnd = (sHour < wHour) || (sHour == wHour && sMin <= wMin);
   bool inWindow = afterRangeCalc && beforeWindowEnd;

   if(!inWindow) return;

   // ── Gestión de posición abierta ───────────────────────────────
   if(HasOpenPosition()) {
      ManagePosition();
      return;
   }

   if(g_tradeExecuted) return;

   // ── PASO 2: Detección y confirmación del breakout ─────────────
   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);

   if(ConfirmOnClose) {
      datetime currentBarTime = iTime(_Symbol, PERIOD_M5, 0);

      // FASE A — Detección (primera vez que el precio cruza el rango)
      if(!g_breakoutPending) {
         if(ask > g_rangeHigh) {
            g_breakoutPending = true;
            g_pendingDir      = "buy";
            g_pendingBarTime  = currentBarTime;
            Print("Breakout detectado BUY en ", TimeToString(TimeCurrent()), " ask=", ask);
         }
         else if(bid < g_rangeLow) {
            g_breakoutPending = true;
            g_pendingDir      = "sell";
            g_pendingBarTime  = currentBarTime;
            Print("Breakout detectado SELL en ", TimeToString(TimeCurrent()), " bid=", bid);
         }
      }

      // FASE B — Confirmación (nueva vela M5 formada)
      if(g_breakoutPending && currentBarTime > g_pendingBarTime) {
         bool stillValid = (g_pendingDir == "buy"  && ask > g_rangeHigh) ||
                           (g_pendingDir == "sell" && bid < g_rangeLow);
         if(!stillValid) {
            Print("False breakout cancelado. Precio regresó al rango.");
            g_breakoutPending = false;
            g_pendingDir      = "";
            g_pendingBarTime  = 0;
         } else {
            ExecuteTrade(g_pendingDir);
         }
      }
   }
   else {
      // Sin confirmación: entrada en primer tick
      if(ask > g_rangeHigh)   ExecuteTrade("buy");
      else if(bid < g_rangeLow) ExecuteTrade("sell");
   }
}

//==================================================================
// CalculateRange — Lee las 3 velas M5: 14:35, 14:40, 14:45 UTC
//==================================================================
void CalculateRange()
{
   // Al abrir la vela de las 14:50 UTC (servidor: rHour:50):
   //   Bar[0] = vela actual  (14:50, aún formándose)
   //   Bar[1] = 14:45 UTC  ← usamos
   //   Bar[2] = 14:40 UTC  ← usamos
   //   Bar[3] = 14:35 UTC  ← usamos
   double h1 = iHigh(_Symbol, PERIOD_M5, 1);
   double h2 = iHigh(_Symbol, PERIOD_M5, 2);
   double h3 = iHigh(_Symbol, PERIOD_M5, 3);
   double l1 = iLow(_Symbol,  PERIOD_M5, 1);
   double l2 = iLow(_Symbol,  PERIOD_M5, 2);
   double l3 = iLow(_Symbol,  PERIOD_M5, 3);

   if(h1 == 0 || h2 == 0 || h3 == 0) {
      Print("ERROR: Datos históricos insuficientes para calcular el rango.");
      return;
   }

   g_rangeHigh  = MathMax(h1, MathMax(h2, h3));
   g_rangeLow   = MathMin(l1, MathMin(l2, l3));
   g_slDistance = g_rangeHigh - g_rangeLow;   // Precio raw (no multiplicar por _Point)

   // ── Filtro de rango ───────────────────────────────────────────
   // BUG FIX [1]: comparar slDistance directo en puntos reales, NO × _Point
   if(g_slDistance < MinSL_Points) {
      Print("Rango FILTRADO (demasiado pequeño): ", DoubleToString(g_slDistance, 2),
            " < MinSL=", MinSL_Points);
      return;
   }
   if(g_slDistance > MaxSL_Points) {
      Print("Rango FILTRADO (demasiado grande): ", DoubleToString(g_slDistance, 2),
            " > MaxSL=", MaxSL_Points);
      return;
   }

   // ── Calcular lotaje UNA SOLA VEZ ─────────────────────────────
   // BUG FIX [6]: cachedLots se calcula aquí, nunca en OnTick
   g_cachedLots = CalculateLotSize(g_slDistance);
   if(g_cachedLots <= 0) {
      Print("ERROR: Lotaje calculado = 0. Día omitido.");
      return;
   }

   g_rangeSet = true;

   Print("── Rango calculado ─────────────────────────────────");
   Print("  RangeHigh : ", DoubleToString(g_rangeHigh, g_digits));
   Print("  RangeLow  : ", DoubleToString(g_rangeLow,  g_digits));
   Print("  SL_Dist   : ", DoubleToString(g_slDistance, g_digits), "  ($", DoubleToString(g_slDistance, 2), ")");
   Print("  Lots      : ", g_cachedLots);
   Print("  Risk      : $", DoubleToString(g_cachedLots * g_slDistance * g_valuePerPoint, 2));

   if(VIS_Enable) VIS_DrawRange();
}

//==================================================================
// CalculateLotSize
//==================================================================
double CalculateLotSize(double slDist)
{
   // BUG FIX [2]: fórmula correcta con unidades consistentes
   // slDist        = precio raw (ej: 2.50 para XAUUSD)
   // g_valuePerPoint = TickValue / TickSize = 1.00 / 0.01 = 100
   // lotsRaw       = RiskAmountUSD / (slDist × g_valuePerPoint)
   // Ejemplo: 100 / (2.50 × 100) = 0.40 lots → riesgo = 0.40 × 2.50 × 100 = $100 ✓

   if(g_valuePerPoint <= 0 || slDist <= 0) {
      Print("ERROR CalculateLotSize: valuePerPoint=", g_valuePerPoint, " slDist=", slDist);
      return 0;
   }

   double lotsRaw = RiskAmountUSD / (slDist * g_valuePerPoint);

   // Redondear al volumeStep del broker
   double lots = MathFloor(lotsRaw / g_volumeStep) * g_volumeStep;
   lots = MathMax(lots, g_volumeMin);
   lots = MathMin(lots, g_volumeMax);
   lots = NormalizeDouble(lots, 2);

   // ── Verificación de margen (BUG FIX [5]) ─────────────────────
   double marginRequired = 0;
   double askNow = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   if(OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots, askNow, marginRequired)) {
      // BUG FIX [7]: ACCOUNT_MARGIN_FREE
      double freeMargin = AccountInfoDouble(ACCOUNT_MARGIN_FREE);
      if(marginRequired > freeMargin * 0.90) {
         double safeMargin = freeMargin * 0.90;
         double reducedLots = MathFloor((safeMargin / marginRequired * lots) / g_volumeStep) * g_volumeStep;
         reducedLots = MathMax(reducedLots, g_volumeMin);
         Print("WARNING: Margen insuficiente. Reduciendo lots de ", lots, " → ", reducedLots);
         lots = reducedLots;
      }
   }

   return lots;
}

//==================================================================
// ExecuteTrade
//==================================================================
void ExecuteTrade(string direction)
{
   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);

   g_tradeDir  = direction;
   g_tradeTime = TimeCurrent();

   if(direction == "buy") {
      g_entryPrice = ask;
      g_slLevel    = NormalizeDouble(g_entryPrice - g_slDistance,               g_digits);
      g_beLevel    = NormalizeDouble(g_entryPrice + g_slDistance * BE_BufferPct / 100.0, g_digits);
      g_tpLevel1   = NormalizeDouble(g_entryPrice + g_slDistance * TP1_RR,      g_digits);
      g_tpLevel2   = NormalizeDouble(g_entryPrice + g_slDistance * TP2_RR,      g_digits);
      g_tpLevel3   = NormalizeDouble(g_entryPrice + g_slDistance * TP3_RR,      g_digits);

      if(!trade.Buy(g_cachedLots, _Symbol, g_entryPrice, g_slLevel, g_tpLevel3, "BreakoutNY BUY")) {
         Print("ERROR Buy: ", trade.ResultRetcode(), " ", trade.ResultRetcodeDescription());
         return;
      }
   }
   else {
      g_entryPrice = bid;
      g_slLevel    = NormalizeDouble(g_entryPrice + g_slDistance,               g_digits);
      g_beLevel    = NormalizeDouble(g_entryPrice - g_slDistance * BE_BufferPct / 100.0, g_digits);
      g_tpLevel1   = NormalizeDouble(g_entryPrice - g_slDistance * TP1_RR,      g_digits);
      g_tpLevel2   = NormalizeDouble(g_entryPrice - g_slDistance * TP2_RR,      g_digits);
      g_tpLevel3   = NormalizeDouble(g_entryPrice - g_slDistance * TP3_RR,      g_digits);

      if(!trade.Sell(g_cachedLots, _Symbol, g_entryPrice, g_slLevel, g_tpLevel3, "BreakoutNY SELL")) {
         Print("ERROR Sell: ", trade.ResultRetcode(), " ", trade.ResultRetcodeDescription());
         return;
      }
   }

   g_tradeExecuted   = true;
   g_breakoutPending = false;
   g_pendingDir      = "";
   g_pendingBarTime  = 0;

   Print("── Trade ejecutado ─────────────────────────────────");
   Print("  Dir    : ", direction);
   Print("  Entry  : ", DoubleToString(g_entryPrice, g_digits));
   Print("  SL     : ", DoubleToString(g_slLevel,    g_digits), "  (dist=", DoubleToString(g_slDistance, g_digits), ")");
   Print("  BE     : ", DoubleToString(g_beLevel,    g_digits));
   Print("  TP1    : ", DoubleToString(g_tpLevel1,   g_digits));
   Print("  TP2    : ", DoubleToString(g_tpLevel2,   g_digits));
   Print("  TP3    : ", DoubleToString(g_tpLevel3,   g_digits));
   Print("  Lots   : ", g_cachedLots);

   if(VIS_Enable) VIS_DrawLevels();
}

//==================================================================
// ManagePosition — BE + Parciales
//==================================================================
void ManagePosition()
{
   ulong ticket = GetOpenPositionTicket();
   if(ticket == 0) return;

   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);

   // ── Breakeven ─────────────────────────────────────────────────
   if(!g_be_activated) {
      bool beCond = (g_tradeDir == "buy"  && bid >= g_beLevel) ||
                    (g_tradeDir == "sell" && ask <= g_beLevel);
      if(beCond) {
         double newSL = NormalizeDouble(g_entryPrice, g_digits);
         if(trade.PositionModify(ticket, newSL, g_tpLevel3)) {
            g_slLevel      = newSL;
            g_be_activated = true;
            Print("BE activado. Nuevo SL=", DoubleToString(newSL, g_digits));
         }
      }
   }

   // ── Cierre parcial TP1 ────────────────────────────────────────
   if(!g_tp1_hit && EnablePartials) {
      bool tp1Cond = (g_tradeDir == "buy"  && bid >= g_tpLevel1) ||
                     (g_tradeDir == "sell" && ask <= g_tpLevel1);
      if(tp1Cond) {
         if(PositionSelectByTicket(ticket)) {
            double posVol    = PositionGetDouble(POSITION_VOLUME);
            double closeVol  = NormalizeDouble(posVol * TP1_ClosePct / 100.0, 2);
            closeVol = MathMax(closeVol, g_volumeMin);
            closeVol = MathMin(closeVol, posVol - g_volumeMin);  // dejar al menos volumeMin
            if(closeVol >= g_volumeMin) {
               trade.PositionClosePartial(ticket, closeVol);
               // SL a entry + pequeño buffer
               double newSL = (g_tradeDir == "buy") ?
                  NormalizeDouble(g_entryPrice + g_slDistance * 0.05, g_digits) :
                  NormalizeDouble(g_entryPrice - g_slDistance * 0.05, g_digits);
               trade.PositionModify(ticket, newSL, g_tpLevel3);
               g_slLevel  = newSL;
            }
         }
         g_tp1_hit = true;
         Print("TP1 alcanzado. Cierre parcial ejecutado.");
      }
   }

   // ── Cierre parcial TP2 ────────────────────────────────────────
   if(g_tp1_hit && !g_tp2_hit && EnablePartials) {
      bool tp2Cond = (g_tradeDir == "buy"  && bid >= g_tpLevel2) ||
                     (g_tradeDir == "sell" && ask <= g_tpLevel2);
      if(tp2Cond) {
         if(PositionSelectByTicket(ticket)) {
            double posVol   = PositionGetDouble(POSITION_VOLUME);
            double closeVol = NormalizeDouble(posVol * TP2_ClosePct / 100.0, 2);
            closeVol = MathMax(closeVol, g_volumeMin);
            closeVol = MathMin(closeVol, posVol - g_volumeMin);
            if(closeVol >= g_volumeMin) {
               trade.PositionClosePartial(ticket, closeVol);
               // SL sube a TP1
               trade.PositionModify(ticket, g_tpLevel1, g_tpLevel3);
               g_slLevel = g_tpLevel1;
            }
         }
         g_tp2_hit = true;
         Print("TP2 alcanzado. Cierre parcial ejecutado. SL→TP1.");
      }
   }
}

//==================================================================
// CloseAllPositions
//==================================================================
void CloseAllPositions(string exitType)
{
   ulong ticket = GetOpenPositionTicket();
   if(ticket == 0) return;

   double closePrice = 0;
   double pnl        = 0;

   if(PositionSelectByTicket(ticket)) {
      closePrice = (g_tradeDir == "buy") ?
         SymbolInfoDouble(_Symbol, SYMBOL_BID) :
         SymbolInfoDouble(_Symbol, SYMBOL_ASK);
      pnl = PositionGetDouble(POSITION_PROFIT);
   }

   trade.PositionClose(ticket);

   Print("Posición cerrada: ", exitType, " | PnL=$", DoubleToString(pnl, 2));

   if(EnableCSV) LogToCSV(exitType, closePrice, pnl);
}

//==================================================================
// LogToCSV
//==================================================================
void LogToCSV(string exitType, double closePrice, double pnl)
{
   if(g_csvHandle == INVALID_HANDLE) return;

   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   string wdays[7];
   wdays[0]="Sun"; wdays[1]="Mon"; wdays[2]="Tue";
   wdays[3]="Wed"; wdays[4]="Thu"; wdays[5]="Fri"; wdays[6]="Sat";

   FileWrite(g_csvHandle,
      StringFormat("%04d.%02d.%02d", dt.year, dt.mon, dt.day),
      StringFormat("%02d:%02d", dt.hour, dt.min),
      wdays[dt.day_of_week],
      g_tradeDir,
      DoubleToString(g_entryPrice,  g_digits),
      DoubleToString(g_slDistance,  g_digits),
      exitType,
      DoubleToString(closePrice,    g_digits),
      DoubleToString(pnl, 2),
      DoubleToString(g_rangeHigh,   g_digits),
      DoubleToString(g_rangeLow,    g_digits),
      DoubleToString(g_slLevel,     g_digits),
      (string)g_be_activated,
      (string)ConfirmOnClose
   );
   FileFlush(g_csvHandle);
}

//==================================================================
// DailyReset
//==================================================================
void DailyReset()
{
   g_rangeHigh       = 0;
   g_rangeLow        = 0;
   g_slDistance      = 0;
   g_cachedLots      = 0;
   g_rangeCalculated = false;
   g_rangeSet        = false;
   g_tradeExecuted   = false;
   g_be_activated    = false;
   g_tp1_hit         = false;
   g_tp2_hit         = false;
   g_breakoutPending = false;
   g_pendingDir      = "";
   g_pendingBarTime  = 0;
   g_entryPrice      = 0;
   g_slLevel         = 0;
   g_tradeDir        = "";
}

//==================================================================
// Helpers
//==================================================================
bool IsTradingDayAllowed()
{
   // BUG FIX [8]: true = OPERA, false = SALTA
   // El filtro retorna el valor del input directamente
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   switch(dt.day_of_week) {
      case 1: return FilterMonday;
      case 2: return FilterTuesday;
      case 3: return FilterWednesday;
      case 4: return FilterThursday;
      case 5: return FilterFriday;
      default: return false;   // Sábado y Domingo
   }
}

bool HasOpenPosition()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--) {
      if(PositionGetTicket(i) > 0) {
         if((int)PositionGetInteger(POSITION_MAGIC) == MagicNumber &&
            PositionGetString(POSITION_SYMBOL) == _Symbol) {
            return true;
         }
      }
   }
   return false;
}

ulong GetOpenPositionTicket()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--) {
      ulong t = PositionGetTicket(i);
      if(t > 0) {
         if((int)PositionGetInteger(POSITION_MAGIC) == MagicNumber &&
            PositionGetString(POSITION_SYMBOL) == _Symbol) {
            return t;
         }
      }
   }
   return 0;
}

//==================================================================
// MÓDULO VISUAL
//==================================================================
void VIS_DrawRange()
{
   if(!VIS_Enable) return;

   datetime t0 = iTime(_Symbol, PERIOD_M5, 3);   // 14:35 UTC
   datetime t1 = iTime(_Symbol, PERIOD_M5, 0);   // 14:50 UTC (barra actual)

   // Rectángulo de rango
   string rName = "BNY_Range";
   ObjectDelete(0, rName);
   ObjectCreate(0, rName, OBJ_RECTANGLE, 0, t0, g_rangeLow, t1, g_rangeHigh);
   ObjectSetInteger(0, rName, OBJPROP_COLOR,        clrDodgerBlue);
   ObjectSetInteger(0, rName, OBJPROP_FILL,         true);
   ObjectSetInteger(0, rName, OBJPROP_BACK,         true);
   ObjectSetInteger(0, rName, OBJPROP_TRANSPARENCY, 75);

   // Líneas High/Low
   string hName = "BNY_RangeH";
   ObjectDelete(0, hName);
   ObjectCreate(0, hName, OBJ_HLINE, 0, 0, g_rangeHigh);
   ObjectSetInteger(0, hName, OBJPROP_COLOR, clrDodgerBlue);
   ObjectSetInteger(0, hName, OBJPROP_STYLE, STYLE_DOT);

   string lName = "BNY_RangeL";
   ObjectDelete(0, lName);
   ObjectCreate(0, lName, OBJ_HLINE, 0, 0, g_rangeLow);
   ObjectSetInteger(0, lName, OBJPROP_COLOR, clrDodgerBlue);
   ObjectSetInteger(0, lName, OBJPROP_STYLE, STYLE_DOT);

   ChartRedraw();
}

void VIS_DrawLevels()
{
   if(!VIS_Enable) return;

   datetime t = TimeCurrent();

   // Flecha de entrada
   string arrName = "BNY_Arrow";
   ObjectDelete(0, arrName);
   ObjectCreate(0, arrName, OBJ_ARROW, 0, t, g_entryPrice);
   if(g_tradeDir == "buy") {
      ObjectSetInteger(0, arrName, OBJPROP_ARROWCODE, 241);   // flecha arriba
      ObjectSetInteger(0, arrName, OBJPROP_COLOR,     clrLime);
   } else {
      ObjectSetInteger(0, arrName, OBJPROP_ARROWCODE, 242);   // flecha abajo
      ObjectSetInteger(0, arrName, OBJPROP_COLOR,     clrRed);
   }
   ObjectSetInteger(0, arrName, OBJPROP_WIDTH, 2);

   // Niveles como líneas horizontales
   struct LevelDef { string name; double price; color clr; ENUM_LINE_STYLE style; int width; };
   LevelDef levels[6];
   levels[0].name="BNY_SL";     levels[0].price=g_slLevel;   levels[0].clr=clrRed;         levels[0].style=STYLE_DOT;   levels[0].width=1;
   levels[1].name="BNY_Entry";  levels[1].price=g_entryPrice;levels[1].clr=clrWhite;       levels[1].style=STYLE_SOLID; levels[1].width=1;
   levels[2].name="BNY_BE";     levels[2].price=g_beLevel;   levels[2].clr=clrCyan;        levels[2].style=STYLE_DASH;  levels[2].width=1;
   levels[3].name="BNY_TP1";    levels[3].price=g_tpLevel1;  levels[3].clr=clrYellow;      levels[3].style=STYLE_SOLID; levels[3].width=1;
   levels[4].name="BNY_TP2";    levels[4].price=g_tpLevel2;  levels[4].clr=clrOrange;      levels[4].style=STYLE_SOLID; levels[4].width=1;
   levels[5].name="BNY_TP3";    levels[5].price=g_tpLevel3;  levels[5].clr=clrLime;        levels[5].style=STYLE_SOLID; levels[5].width=2;

   for(int i = 0; i < 6; i++) {
      ObjectDelete(0, levels[i].name);
      ObjectCreate(0, levels[i].name, OBJ_HLINE, 0, 0, levels[i].price);
      ObjectSetInteger(0, levels[i].name, OBJPROP_COLOR, levels[i].clr);
      ObjectSetInteger(0, levels[i].name, OBJPROP_STYLE, levels[i].style);
      ObjectSetInteger(0, levels[i].name, OBJPROP_WIDTH, levels[i].width);
   }

   // Etiqueta resumen
   string lblName = "BNY_Label";
   ObjectDelete(0, lblName);
   ObjectCreate(0, lblName, OBJ_LABEL, 0, 0, 0);
   ObjectSetInteger(0, lblName, OBJPROP_CORNER,    CORNER_LEFT_UPPER);
   ObjectSetInteger(0, lblName, OBJPROP_XDISTANCE, 10);
   ObjectSetInteger(0, lblName, OBJPROP_YDISTANCE, 50);
   ObjectSetString(0, lblName, OBJPROP_FONT,       "Courier New");
   ObjectSetInteger(0, lblName, OBJPROP_FONTSIZE,  9);
   ObjectSetInteger(0, lblName, OBJPROP_COLOR,     clrWhite);

   string dir = (g_tradeDir == "buy") ? "▲ BUY" : "▼ SELL";
   ObjectSetString(0, lblName, OBJPROP_TEXT,
      StringFormat("BreakoutNY v8 XAUUSD | %s | SL: $%.2f | TP3: $%.2f | Lots: %.2f",
         dir, g_slDistance, g_slDistance * TP3_RR, g_cachedLots));

   ChartRedraw();
}

void VIS_CleanAll()
{
   string names[12];
   names[0]="BNY_Range";  names[1]="BNY_RangeH"; names[2]="BNY_RangeL";
   names[3]="BNY_Arrow";  names[4]="BNY_SL";     names[5]="BNY_Entry";
   names[6]="BNY_BE";     names[7]="BNY_TP1";    names[8]="BNY_TP2";
   names[9]="BNY_TP3";    names[10]="BNY_Label"; names[11]="";

   for(int i = 0; i < 11; i++) {
      ObjectDelete(0, names[i]);
   }
   ChartRedraw();
}
