//+------------------------------------------------------------------+
//|           BreakoutNY_Calibrator_XAUUSD.mq5                       |
//|   Script de calibración — analiza distribución del rango NY      |
//|   para XAUUSD y sugiere MinSL_Points / MaxSL_Points              |
//|                                                                  |
//|   INSTRUCCIONES:                                                 |
//|   1. Abrir un gráfico de XAUUSD M5 en MT5                        |
//|   2. Ejecutar este script (drag & drop o F5)                     |
//|   3. Leer resultados en el tab "Expertos"                        |
//|   4. Copiar MinSL_Points / MaxSL_Points al EA principal          |
//|   5. LUEGO correr el backtest                                    |
//+------------------------------------------------------------------+
#property copyright "BreakoutNY Calibrator v1.0"
#property version   "1.00"
#property script_show_inputs

input int    LookbackDays  = 500;   // Días de historial a analizar (mín. 500 recomendado)
input int    ServerOffset  = 2;     // Offset UTC del servidor (FundingPips = 2)
input string OutputFile    = "BreakoutNY_Calibrator_XAUUSD.csv";

//+------------------------------------------------------------------+
void OnStart()
{
   Print("╔══════════════════════════════════════════════════╗");
   Print("║  BreakoutNY Calibrator — XAUUSD — FundingPips   ║");
   Print("╚══════════════════════════════════════════════════╝");
   Print("Símbolo      : ", _Symbol);
   Print("LookbackDays : ", LookbackDays);
   Print("ServerOffset : UTC+", ServerOffset);
   Print("Analizando... (puede tardar unos segundos)");

   // ── Verificar símbolo ─────────────────────────────────────────
   if(_Symbol != "XAUUSD") {
      Print("⚠ ADVERTENCIA: El script está configurado para XAUUSD.");
      Print("  Símbolo actual: ", _Symbol, ". Continúa igualmente...");
   }

   // ── Cargar datos M5 ───────────────────────────────────────────
   datetime endTime   = TimeCurrent();
   datetime startTime = endTime - (datetime)(LookbackDays * 86400 * 2); // buffer x2 para fines de semana

   MqlRates rates[];
   int bars = CopyRates(_Symbol, PERIOD_M5, startTime, endTime, rates);

   if(bars <= 0) {
      Print("ERROR: No se pudieron cargar datos M5. Bars=", bars);
      Print("  → Asegúrate de tener historial suficiente descargado (Herramientas → Centro de Servicio)");
      return;
   }
   Print("Barras M5 cargadas: ", bars);

   // ── Arrays para estadísticas ──────────────────────────────────
   double  ranges[];
   string  rangeDates[];
   int     rangeWeekdays[];
   ArrayResize(ranges, 0);
   ArrayResize(rangeDates, 0);
   ArrayResize(rangeWeekdays, 0);

   // ── Hora objetivo en servidor ─────────────────────────────────
   // 14:35, 14:40, 14:45 UTC → servidor: (14+offset):35, :40, :45
   int targetHour = 14 + ServerOffset;   // 16 para UTC+2

   // ── CSV de detalle ────────────────────────────────────────────
   int csvHandle = FileOpen(OutputFile, FILE_WRITE | FILE_CSV | FILE_ANSI | FILE_SHARE_READ, ",");
   if(csvHandle == INVALID_HANDLE) {
      Print("ERROR: No se puede crear el archivo CSV: ", OutputFile);
      Print("  Error code: ", GetLastError());
      // Continuar sin CSV
   } else {
      FileWrite(csvHandle,
         "Date","Weekday",
         "High_1435UTC","Low_1435UTC",
         "High_1440UTC","Low_1440UTC",
         "High_1445UTC","Low_1445UTC",
         "RangeHigh","RangeLow","RangeDist_Raw",
         "Note"
      );
   }

   // ── Procesar barras ───────────────────────────────────────────
   int    daysProcessed  = 0;
   int    daysSkipped    = 0;
   datetime lastDay = 0;
   string wdays[7];
   wdays[0]="Dom"; wdays[1]="Lun"; wdays[2]="Mar";
   wdays[3]="Mie"; wdays[4]="Jue"; wdays[5]="Vie"; wdays[6]="Sab";

   for(int i = 0; i < bars - 5 && daysProcessed < LookbackDays; i++) {
      MqlDateTime dt;
      TimeToStruct(rates[i].time, dt);

      // Saltar fines de semana
      if(dt.day_of_week == 0 || dt.day_of_week == 6) continue;

      // Buscar la vela de las (targetHour):35
      if(dt.hour != targetHour || dt.min != 35) continue;

      // Una sola vez por día
      datetime currentDay = (datetime)StringToTime(
         StringFormat("%04d.%02d.%02d 00:00:00", dt.year, dt.mon, dt.day));
      if(currentDay == lastDay) continue;
      lastDay = currentDay;

      // Verificar que las siguientes 2 barras sean :40 y :45
      if(i + 2 >= bars) continue;

      MqlDateTime dt1, dt2;
      TimeToStruct(rates[i+1].time, dt1);
      TimeToStruct(rates[i+2].time, dt2);

      string note = "";
      bool valid  = true;

      if(dt1.hour != targetHour || dt1.min != 40) {
         note = "Falta vela " + (string)targetHour + ":40";
         valid = false;
         daysSkipped++;
      }
      else if(dt2.hour != targetHour || dt2.min != 45) {
         note = "Falta vela " + (string)targetHour + ":45";
         valid = false;
         daysSkipped++;
      }

      // Velas: i=14:35, i+1=14:40, i+2=14:45 (en hora servidor)
      double h1 = rates[i].high;
      double l1 = rates[i].low;
      double h2 = rates[i+1].high;
      double l2 = rates[i+1].low;
      double h3 = rates[i+2].high;
      double l3 = rates[i+2].low;

      double rHigh = MathMax(h1, MathMax(h2, h3));
      double rLow  = MathMin(l1, MathMin(l2, l3));
      double rDist = rHigh - rLow;

      // Guardar CSV
      if(csvHandle != INVALID_HANDLE) {
         FileWrite(csvHandle,
            StringFormat("%04d.%02d.%02d", dt.year, dt.mon, dt.day),
            wdays[dt.day_of_week],
            DoubleToString(h1, 2), DoubleToString(l1, 2),
            DoubleToString(h2, 2), DoubleToString(l2, 2),
            DoubleToString(h3, 2), DoubleToString(l3, 2),
            DoubleToString(rHigh, 2),
            DoubleToString(rLow,  2),
            DoubleToString(rDist, 2),
            valid ? "OK" : note
         );
      }

      if(!valid) continue;

      // Agregar al array de rangos
      int sz = ArraySize(ranges);
      ArrayResize(ranges,      sz + 1);
      ArrayResize(rangeDates,  sz + 1);
      ArrayResize(rangeWeekdays, sz + 1);
      ranges[sz]       = rDist;
      rangeDates[sz]   = StringFormat("%04d.%02d.%02d", dt.year, dt.mon, dt.day);
      rangeWeekdays[sz] = dt.day_of_week;

      daysProcessed++;
   }

   if(csvHandle != INVALID_HANDLE) {
      FileFlush(csvHandle);
      FileClose(csvHandle);
   }

   // ── Validar que hay datos ─────────────────────────────────────
   int n = ArraySize(ranges);
   if(n < 10) {
      Print("ERROR: Solo se encontraron ", n, " días válidos.");
      Print("  → Verifica: 1) ServerOffset=", ServerOffset, " correcto?");
      Print("  → Verifica: 2) Historial M5 de XAUUSD descargado en MT5?");
      return;
   }

