      return;
   }
   Print("Barras M5 cargadas: ", bars);

   // ── Arrays para estadísticas ──────────────────────────────────
   double  ranges[];
   string  rangeDates[];
   int     rangeWeekdays[];
   ArrayResize(ranges, 0);
   ArrayResize(rangeDates, 0);
   ArrayResize(rangeWeekdays, 0);

   // ── Hora objetivo en servidor ─────────────────────────────────
   // 14:35, 14:40, 14:45 UTC → servidor: (14+offset):35, :40, :45
   int targetHour = 14 + ServerOffset;   // 16 para UTC+2

   // ── CSV de detalle ────────────────────────────────────────────
   int csvHandle = FileOpen(OutputFile, FILE_WRITE | FILE_CSV | FILE_ANSI | FILE_SHARE_READ, ",");
   if(csvHandle == INVALID_HANDLE) {
      Print("ERROR: No se puede crear el archivo CSV: ", OutputFile);
      Print("  Error code: ", GetLastError());
