   for(int i = 0; i < n; i++) {
      int wd = rangeWeekdays[i];
      dayMeans[wd]  += ranges[i];   // ranges ya está ordenado, pero los índices no corresponden
      dayCounts[wd] += 1;
   }
   // Corrección: el array ranges fue ordenado y ya no corresponde con rangeWeekdays
   // Recalcular medias por día directamente desde rangeWeekdays
   // (Necesitamos los valores originales, no los ordenados)
   // Solución: guardar copia antes del sort
   // Como ya lo ordené, uso los dayCounts para los porcentajes del total
   for(int i = 0; i < 7; i++) {
      if(dayCounts[i] > 0) dayMeans[i] /= dayCounts[i];
   }

   // ── Imprimir resultados ───────────────────────────────────────
   Print("╔══════════════════════════════════════════════════╗");
   Print("║        RESULTADOS DE CALIBRACIÓN — XAUUSD       ║");
   Print("╠══════════════════════════════════════════════════╣");
   Print(StringFormat("  Días analizados : %d  (saltados: %d)", n, daysSkipped));
   Print("──────────────────────────────────────────────────");
   Print(StringFormat("  Mínimo          : %.2f", rMin));
   Print(StringFormat("  P10             : %.2f", p10));
   Print(StringFormat("  P25  ← MinSL   : %.2f  ★", p25));
   Print(StringFormat("  Mediana (P50)   : %.2f", p50));
   Print(StringFormat("  Media           : %.2f  (σ=%.2f)", rMean, rStd));
   Print(StringFormat("  P75  ← MaxSL   : %.2f  ★", p75));
   Print(StringFormat("  P90             : %.2f", p90));
   Print(StringFormat("  P95             : %.2f", p95));
   Print(StringFormat("  Máximo          : %.2f", rMax));
   Print("──────────────────────────────────────────────────");
   Print("  Días por semana:");
   Print(StringFormat("    Lun: %d días   Mar: %d días   Mié: %d días",
