const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  HeadingLevel, AlignmentType, BorderStyle, WidthType, ShadingType,
  VerticalAlign, PageNumber, PageBreak, LevelFormat, UnderlineType
} = require('docx');
const fs = require('fs');

// ── Helpers ───────────────────────────────────────────────────
const border = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const borders = { top: border, bottom: border, left: border, right: border };

function cell(text, opts = {}) {
  const { bold = false, bg = "FFFFFF", align = AlignmentType.LEFT, color = "000000" } = opts;
  return new TableCell({
    borders,
    width: { size: opts.width || 1500, type: WidthType.DXA },
    shading: { fill: bg, type: ShadingType.CLEAR },
    margins: { top: 80, bottom: 80, left: 120, right: 120 },
    verticalAlign: VerticalAlign.CENTER,
    children: [new Paragraph({
      alignment: align,
      children: [new TextRun({ text: String(text), bold, color, font: "Arial", size: 18 })]
    })]
  });
}

function hcell(text, opts = {}) {
  return cell(text, { bold: true, bg: "1F3864", color: "FFFFFF", ...opts });
}

function statusCell(text, isGood) {
  return cell(text, { bold: true, bg: isGood ? "E2EFDA" : "FCE4D6", color: isGood ? "375623" : "9C0006" });
}

function heading1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 360, after: 120 },
    children: [new TextRun({ text, bold: true, size: 28, color: "1F3864", font: "Arial" })]
  });
}

function heading2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 240, after: 80 },
    children: [new TextRun({ text, bold: true, size: 22, color: "2E75B6", font: "Arial" })]
  });
}

function para(runs) {
  if (typeof runs === 'string') runs = [{ text: runs }];
  return new Paragraph({
    spacing: { before: 60, after: 100 },
    children: runs.map(r => new TextRun({ font: "Arial", size: 20, ...r }))
  });
}

function alertBox(text, type = "warning") {
  const bg = type === "critical" ? "FCE4D6" : type === "good" ? "E2EFDA" : "FFF2CC";
  const color = type === "critical" ? "9C0006" : type === "good" ? "375623" : "7F6000";
  return new Paragraph({
    spacing: { before: 120, after: 120 },
    border: {
      left: { style: BorderStyle.THICK, size: 20, color: color.length === 6 ? color : "CC0000", space: 8 }
    },
    indent: { left: 360 },
    children: [new TextRun({ text, font: "Arial", size: 20, color, bold: type === "critical" })]
  });
}

function spacer() {
  return new Paragraph({ spacing: { before: 80, after: 80 }, children: [new TextRun("")] });
}

// ── Document ──────────────────────────────────────────────────
