   }

   double lotsRaw = RiskAmountUSD / (slDist * g_valuePerPoint);

   // Redondear al volumeStep del broker
   double lots = MathFloor(lotsRaw / g_volumeStep) * g_volumeStep;
   lots = MathMax(lots, g_volumeMin);
   lots = MathMin(lots, g_volumeMax);
   lots = NormalizeDouble(lots, 2);

   // ── Verificación de margen (BUG FIX [5]) ─────────────────────
   double marginRequired = 0;
   double askNow = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   if(OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots, askNow, marginRequired)) {
      // BUG FIX [7]: ACCOUNT_MARGIN_FREE
      double freeMargin = AccountInfoDouble(ACCOUNT_MARGIN_FREE);
      if(marginRequired > freeMargin * 0.90) {
         double safeMargin = freeMargin * 0.90;
         double reducedLots = MathFloor((safeMargin / marginRequired * lots) / g_volumeStep) * g_volumeStep;
