function cell(text, { bold=false, bg="FFFFFF", align=AlignmentType.LEFT,
  color="1a1a1a", w=1500, italic=false, sz=19, vAlign=VerticalAlign.CENTER } = {}) {
  return new TableCell({
    borders: bdrs,
    width: { size: w, type: WidthType.DXA },
    shading: { fill: bg, type: ShadingType.CLEAR },
    margins: { top: 90, bottom: 90, left: 140, right: 140 },
    verticalAlign: vAlign,
    children: [new Paragraph({ alignment: align,
      children: [new TextRun({ text: String(text), bold, color, font:"Calibri", size:sz, italics:italic })] })],
  });
}
