}

function p(text, { sz=20, color="1a1a1a", bold=false, spacing={before:60,after:100} } = {}) {
  const runs = typeof text === 'string'
    ? [new TextRun({ text, font:"Calibri", size:sz, color, bold })]
    : text.map(r => new TextRun({ font:"Calibri", size:20, color:"1a1a1a", ...r }));
  return new Paragraph({ spacing, children: runs });
}
function bullet(text, opts={}) {
  return new Paragraph({ numbering:{ reference:"bul", level:0 }, spacing:{before:40,after:40},
    children:[new TextRun({ text, font:"Calibri", size:20, color:"1a1a1a", ...opts })] });
}
function nb(text, opts={}) {
