        rows:[
          new TableRow({children:[hcell("Métrica"),hcell("V1 (nuevo)",{align:AlignmentType.CENTER}),hcell("Objetivo FundingPips",{align:AlignmentType.CENTER})]}),
          new TableRow({children:[cell("Net Profit bruto (5 años)"),gcell("+$1,880",{align:AlignmentType.CENTER}),bcell("> $0",{align:AlignmentType.CENTER})]}),
          new TableRow({children:[cell("Net Profit neto (c/ spreads)"),gcell("+$1,389",{align:AlignmentType.CENTER}),bcell("> $0",{align:AlignmentType.CENTER})]}),
          new TableRow({children:[cell("Profit Factor"),ycell("1.164  ⚠",{align:AlignmentType.CENTER}),bcell("≥ 1.35",{align:AlignmentType.CENTER})]}),
          new TableRow({children:[cell("MaxDD (balance)"),rcell("16.85%  ✖",{align:AlignmentType.CENTER}),bcell("< 8%",{align:AlignmentType.CENTER})]}),
          new TableRow({children:[cell("Trades totales"),bcell("373",{align:AlignmentType.CENTER}),bcell("—",{align:AlignmentType.CENTER})]}),
          new TableRow({children:[cell("Peor trade"),gcell("−$100.00  ✅",{align:AlignmentType.CENTER}),bcell("< −$500",{align:AlignmentType.CENTER})]}),
          new TableRow({children:[cell("Mejor trade"),bcell("+$299.88",{align:AlignmentType.CENTER}),bcell("—",{align:AlignmentType.CENTER})]}),
          new TableRow({children:[cell("Avg ganancia / SL hit"),gcell("−$96.30  ✅",{align:AlignmentType.CENTER}),bcell("≈ −$100",{align:AlignmentType.CENTER})]}),
          new TableRow({children:[cell("Racha pérdidas consecutivas"),gcell("4 trades max  ✅",{align:AlignmentType.CENTER}),bcell("< 10",{align:AlignmentType.CENTER})]}),
          new TableRow({children:[cell("Meses positivos"),ycell("26/62 (42%)  ⚠",{align:AlignmentType.CENTER}),bcell("> 50%",{align:AlignmentType.CENTER})]}),
        ]}),
      sp(),
      alert("El bug de riesgo está corregido: el peor trade es exactamente −$100 y la pérdida media en SL es $96.30 (diferencia por spread). El riesgo ya está bajo control. El problema ahora es de rentabilidad pura: el PF (1.164) y el MaxDD (16.85%) necesitan optimización antes de la cuenta real.", "info"),

