{"language": "plaintext", "code": "//+------------------------------------------------------------------+
//|        BreakoutNY_StatAnalyzer_XAUUSD.mq5                        |
//|   Script de análisis estadístico — Sesión NY — XAUUSD            |
//|   Genera CSV con métricas quirúrgicas del comportamiento del      |
//|   precio post-apertura de NY para calibración de la estrategia.  |
//|                                                                   |
//|   OUTPUT: BreakoutNY_Stats_XAUUSD.csv                            |
//|                                                                   |
//|   MÉTRICAS ANALIZADAS:                                            |
//|   1. Vela exacta del breakout (cuántas M5 post-apertura)          |
//|   2. Rentabilidad de TP1 / TP2 / TP3 por breakout                |
//|   3. Rango del pre-NY (las 3 velas antes de 14:50 UTC)           |
//|   4. Distancia máxima favorable (MAE/MFE del movimiento)         |
//|   5. Tiempo hasta TP1/2/3 o hasta SL                             |
//|   6. Correlación rango → distancia alcanzada                      |
//|   7. Distribución de rangos por cuartil y su win rate            |
//|   8. Sesgo direccional por día de semana                         |
//|   9. Tasa de reversión post-breakout                             |
//|  10. Ventana óptima de entrada (qué vela M5 es la más rentable) |
//+------------------------------------------------------------------+
#property copyright "BreakoutNY StatAnalyzer v1.0"
#property version   "1.00"
#property script_show_inputs

#include <Trade\Trade.mqh>

//==================================================================
// INPUTS
//==================================================================
input group "=== HORARIO (UTC) ==="
input int  ServerOffsetHours = 2;     // Offset UTC del servidor (FundingPips=2)

// Horario expresado en hora UTC, convertido internamente a hora servidor
// Ventana de referencia: 14:35–14:45 UTC = 3 velas del rango
// Ventana de apertura NY: 14:50 UTC
// Cierre forzoso: 17:00 UTC (26 velas M5 post-apertura)
// Sesión analizada: 14:35–17:00 UTC

input group "=== RIESGO DE REFERENCIA ==="
input double SL_Reference_USD = 100.0; // Riesgo de referencia ($) para calcular RR real
input double ContractSize_Ref = 100.0; // Tamaño de contrato XAUUSD (oz por lote)

input group "=== FILTROS DE RANGO ==="
input double MinRange_Filter  = 2.0;   // Ignorar días con rango < N puntos (ruido)
input double MaxRange_Filter  = 80.0;  // Ignorar días con rango > N puntos (outlier)

input group "=== PERÍODO DE ANÁLISIS ==="
input int    YearFrom = 2021;  // Año inicio
input int    YearTo   = 2026;  // Año fin (inclusivo)

input group "=== ARCHIVO DE SALIDA ==="
input string OutputFile = "BreakoutNY_Stats_XAUUSD.csv";

//==================================================================
// CONSTANTES INTERNAS
//==================================================================
// Todos los tiempos en hora SERVIDOR (UTC + ServerOffsetHours)
// FundingPips UTC+2: NY = 14:50 UTC = 16:50 servidor
#define BARS_M5_IN_SESSION  26   // 14:50–17:00 UTC = 130 min / 5 = 26 velas

//==================================================================
// ESTRUCTURA DE RESULTADO POR DÍA
//==================================================================
struct DayResult
{
   datetime date;           // Fecha del día
   int      weekday;        // 0=Dom, 1=Lun, 2=Mar, 3=Mié, 4=Jue, 5=Vie, 6=Sáb
   double   range;          // rangeHigh - rangeLow (puntos de precio)
   double   rangeHigh;      // Máximo de las 3 velas de pre-NY
   double   rangeLow;       // Mínimo de las 3 velas de pre-NY
   double   openNY;         // Precio de apertura (open vela 14:50 servidor)

   // Dirección del breakout
   int      breakoutDir;    // +1=al alza, -1=a la baja, 0=no rompió
   int      breakoutCandle; // Vela M5 en que ocurrió el breakout (1=primera, 0=nunca)

   // Distancias máximas
   double   maxFavorable;   // Máximo movimiento a favor del breakout (en puntos)
   double   maxAdverse;     // Máximo movimiento en contra del breakout (en puntos)
   double   closeNY;        // Precio al cierre forzoso 17:00 UTC

   // Logros de TPs (en múltiplos del rango = RR equivalente)
   int      hitTP1;         // 1 = alcanzó 1×Rango desde entry
   int      hitTP2;         // 1 = alcanzó 2×Rango
   int      hitTP3;         // 1 = alcanzó 3×Rango
   int      hitSL;          // 1 = retrocedió al lado opuesto del rango (SL)

   // Vela en que alcanzó cada TP
   int      candleTP1;      // 0 si no lo alcanzó
   int      candleTP2;
   int      candleTP3;
   int      candleSL;

   // Distancias absolutas desde entry
   double   distTP1;        // range * 1 (referencia)
   double   distTP2;        // range * 2
   double   distTP3;        // range * 3

   // PnL simulado con riesgo $100 (para verificar rentabilidad)
   double   pnlSimTP3;      // Si TP3 → +$300, si SL → -$100, sino proportional
   double   pnlSimTP1;      // Si TP1 → +$100, si SL → -$100

   // Extra
   double   retracePct;     // % de retroceso del movimiento antes del cierre
   int      reversedAfterBreak; // 1 = rompió pero terminó en el lado contrario
};

//==================================================================
// VARIABLES GLOBALES
//==================================================================
int    g_csvHandle = INVALID_HANDLE;
int    g_totalDays = 0;

//==================================================================
// SCRIPT ENTRY POINT
//==================================================================
void OnStart()
{
   Print("╔══════════════════════════════════════════════════════╗");
   Print("║  BreakoutNY StatAnalyzer v1.0 — XAUUSD NY Session   ║");
   Print("║  Período: ", YearFrom, "–", YearTo, "  |  Riesgo ref: $", SL_Reference_USD, "  ║");
   Print("╚══════════════════════════════════════════════════════╝");

   // Verificar símbolo
   if(_Symbol != "XAUUSD" && StringFind(_Symbol,"XAU") < 0 && StringFind(_Symbol,"GOLD") < 0)
      Print("AVISO: Símbolo=", _Symbol, ". Optimizado para XAUUSD. Verifique specs.");

   // Abrir CSV
   g_csvHandle = FileOpen(OutputFile,
                          FILE_WRITE | FILE_CSV | FILE_ANSI | FILE_COMMON, ',');
   if(g_csvHandle == INVALID_HANDLE) {
      Print("ERROR: No se pudo crear ", OutputFile, " — Error: ", GetLastError());
      return;
   }

   // Escribir cabecera del CSV
   WriteCSVHeader();

   // Necesitamos M5
   if(Period() != PERIOD_M5) {
      Print("AVISO: Abra el gráfico en M5 antes de correr este script.");
      Print("       Intentando trabajar con datos M5 desde el histórico...");
   }

   // Calcular offset servidor en segundos
   int serverOffsetSec = ServerOffsetHours * 3600;

   // Obtener cantidad de barras M5 disponibles
   int totalBars = iBars(_Symbol, PERIOD_M5);
   Print("Barras M5 disponibles: ", totalBars);

   if(totalBars < 100) {
      Print("ERROR: Datos insuficientes. Descargue el histórico M5 de XAUUSD.");
      FileClose(g_csvHandle);
      return;
   }

   // Arrays para estadísticas globales
   DayResult results[];
   int       resultCount = 0;
   ArrayResize(results, 2000); // pre-alocar para ~5 años de días operables

   // ── ITERACIÓN PRINCIPAL: recorrer el histórico buscando días NY ──
   // Lógica: para cada día (2021–2026), buscar la vela de 14:50 UTC
   // y analizar el rango previo + comportamiento post-apertura

   // Convertir fecha inicio/fin a datetime
   datetime dtFrom = StringToTime(IntegerToString(YearFrom) + ".01.01 00:00");
   datetime dtTo   = StringToTime(IntegerToString(YearTo)   + ".12.31 23:59");

   Print("Analizando desde ", TimeToString(dtFrom), " hasta ", TimeToString(dtTo));

   // Hora de referencia en hora SERVIDOR
   // NY open = 14:50 UTC → 14:50 + ServerOffset en hora servidor
   // FundingPips UTC+2: NY open = 16:50 servidor
   // Velas del rango pre-NY: 14:35, 14:40, 14:45 UTC → 16:35, 16:40, 16:45 srv
   // Cierre forzoso: 17:00 UTC → 19:00 servidor
   int nyOpenHour_srv   = (14 + ServerOffsetHours) % 24;
   int nyOpenMin_srv    = 50;
   int rangeStartHour_srv = (14 + ServerOffsetHours) % 24;
   int rangeStartMin_srv  = 35;
   int closeHour_srv    = (17 + ServerOffsetHours) % 24;
   int closeMin_srv     = 0;

   Print("Hora servidor NY open: ", nyOpenHour_srv, ":", nyOpenMin_srv);
   Print("Hora servidor rango inicio: ", rangeStartHour_srv, ":", rangeStartMin_srv);
   Print("Hora servidor cierre: ", closeHour_srv, ":", closeMin_srv);

   // Recorrer barras de más antigua a más reciente
   // Buscamos la vela exacta de las rangeStartHour:rangeStartMin
   int barsProcessed = 0;
   string lastDay    = "";

   for(int i = totalBars - 1; i >= 26; i--)
   {
      datetime barTime = iTime(_Symbol, PERIOD_M5, i);

      // Filtrar por rango de años
      MqlDateTime mdt;
      TimeToStruct(barTime, mdt);
      if(mdt.year < YearFrom || mdt.year > YearTo) continue;

      // Buscar velas exactamente a las rangeStartHour:35 servidor
      if(mdt.hour != rangeStartHour_srv || mdt.min != rangeStartMin_srv) continue;

      // Ignorar fines de semana
      if(mdt.day_of_week == 0 || mdt.day_of_week == 6) continue;

      // Verificar que no procesamos este día ya
      string dayKey = IntegerToString(mdt.year) + "-" +
                      IntegerToString(mdt.mon)  + "-" +
                      IntegerToString(mdt.day);
      if(dayKey == lastDay) continue;
      lastDay = dayKey;

      // ── PASO 1: Calcular rango (3 velas: 14:35, 14:40, 14:45 UTC) ──
      // Bar i   = 14:35 srv (16:35 UTC+2)
      // Bar i-1 = 14:40 srv
      // Bar i-2 = 14:45 srv
      double h0 = iHigh(_Symbol, PERIOD_M5, i);
      double l0 = iLow (_Symbol, PERIOD_M5, i);
      double h1 = iHigh(_Symbol, PERIOD_M5, i-1);
      double l1 = iLow (_Symbol, PERIOD_M5, i-1);
      double h2 = iHigh(_Symbol, PERIOD_M5, i-2);
      double l2 = iLow (_Symbol, PERIOD_M5, i-2);

      double rangeHigh = MathMax(h0, MathMax(h1, h2));
      double rangeLow  = MathMin(l0, MathMin(l1, l2));
      double rangeDist = NormalizeDouble(rangeHigh - rangeLow, 2);

      // Filtrar rangos extremos
      if(rangeDist < MinRange_Filter || rangeDist > MaxRange_Filter) continue;

      // ── PASO 2: Encontrar vela de apertura NY (i-3 = 14:50 srv) ──
      if(i < 3 + BARS_M5_IN_SESSION + 2) continue; // Suficientes barras hacia adelante
      int nyOpenIdx = i - 3; // vela de 14:50 servidor

      // Verificar que es la vela correcta
      datetime nyTime = iTime(_Symbol, PERIOD_M5, nyOpenIdx);
      MqlDateTime nyMdt;
      TimeToStruct(nyTime, nyMdt);
      if(nyMdt.hour != nyOpenHour_srv || nyMdt.min != nyOpenMin_srv) {
         // Buscar la vela correcta en un margen de ±1 barra
         bool found = false;
         for(int delta = -2; delta <= 2; delta++) {
            if(nyOpenIdx + delta < 0) continue;
            datetime t2 = iTime(_Symbol, PERIOD_M5, nyOpenIdx + delta);
            MqlDateTime m2; TimeToStruct(t2, m2);
            if(m2.hour == nyOpenHour_srv && m2.min == nyOpenMin_srv) {
               nyOpenIdx += delta; found = true; break;
            }
         }
         if(!found) continue;
      }

      double openNY     = iOpen(_Symbol, PERIOD_M5, nyOpenIdx);
      double distTP1    = rangeDist * 1.0;
      double distTP2    = rangeDist * 2.0;
      double distTP3    = rangeDist * 3.0;

      // ── PASO 3: Seguir el precio vela a vela hasta las 17:00 ──
      DayResult dr;
      ZeroMemory(dr);
      dr.date        = barTime;
      dr.weekday     = mdt.day_of_week; // 1=Lun ... 5=Vie
      dr.range       = rangeDist;
      dr.rangeHigh   = rangeHigh;
      dr.rangeLow    = rangeLow;
      dr.openNY      = openNY;
      dr.distTP1     = distTP1;
      dr.distTP2     = distTP2;
      dr.distTP3     = distTP3;

      double maxBullish = 0; // Máx movimiento al alza desde rangeHigh
      double maxBearish = 0; // Máx movimiento a la baja desde rangeLow
      double lastClose  = openNY;

      bool   brokeBull = false;
      bool   brokeBear = false;

      // Analizar las 26 velas post-apertura (14:50 → 17:00 UTC)
      // En el array de barras: nyOpenIdx - 1 = primera vela (más reciente = menor índice)
      // OJO: iTime/iHigh etc. van de más reciente (idx=0) a más antigua (idx=N)
      // nyOpenIdx es la vela 14:50 → velas posteriores son nyOpenIdx-1, nyOpenIdx-2...
      for(int c = 1; c <= BARS_M5_IN_SESSION; c++)
      {
         int barIdx = nyOpenIdx - c;
         if(barIdx < 0) break;

         datetime cTime = iTime(_Symbol, PERIOD_M5, barIdx);
         MqlDateTime cMdt; TimeToStruct(cTime, cMdt);

         // Parar si llegamos a las 17:00 UTC (19:00 servidor)
         if(cMdt.hour == closeHour_srv && cMdt.min == closeMin_srv) {
            lastClose = iOpen(_Symbol, PERIOD_M5, barIdx);
            break;
         }
         // Parar si superamos la hora de cierre
         if(cMdt.hour > closeHour_srv || (cMdt.hour == closeHour_srv && cMdt.min > closeMin_srv)) {
            lastClose = iClose(_Symbol, PERIOD_M5, barIdx + 1);
            break;
         }

         double hi = iHigh (_Symbol, PERIOD_M5, barIdx);
         double lo = iLow  (_Symbol, PERIOD_M5, barIdx);
         double cl = iClose(_Symbol, PERIOD_M5, barIdx);
         lastClose = cl;

         // ─ Detectar primer breakout ─
         bool bullBreak = (hi > rangeHigh);
         bool bearBreak = (lo  < rangeLow);

         if(bullBreak && !brokeBull && !brokeBear) {
            brokeBull              = true;
            dr.breakoutDir         = 1;
            dr.breakoutCandle      = c;
         }
         if(bearBreak && !brokeBear && !brokeBull) {
            brokeBear              = true;
            dr.breakoutDir         = -1;
            dr.breakoutCandle      = c;
         }

         // ─ Tracking de movimiento favorable / adverso ─
         if(brokeBull) {
            double favorMove = hi - rangeHigh;
            double adverMove = rangeHigh - lo;
            if(favorMove > maxBullish) maxBullish = favorMove;
            if(adverMove > maxBearish) maxBearish = adverMove;

            // Hits de TP (desde rangeHigh como entry breakout)
            if(dr.hitTP1 == 0 && hi >= rangeHigh + distTP1) { dr.hitTP1 = 1; dr.candleTP1 = c; }
            if(dr.hitTP2 == 0 && hi >= rangeHigh + distTP2) { dr.hitTP2 = 1; dr.candleTP2 = c; }
            if(dr.hitTP3 == 0 && hi >= rangeHigh + distTP3) { dr.hitTP3 = 1; dr.candleTP3 = c; }
            // SL = precio cae por debajo de rangeLow (rango del otro lado)
            if(dr.hitSL  == 0 && lo  <= rangeLow)           { dr.hitSL  = 1; dr.candleSL  = c; }
         }
         else if(brokeBear) {
            double favorMove = rangeLow - lo;
            double adverMove = hi - rangeLow;
            if(favorMove > maxBearish) maxBearish = favorMove;
            if(adverMove > maxBullish) maxBullish = adverMove;

            if(dr.hitTP1 == 0 && lo  <= rangeLow  - distTP1) { dr.hitTP1 = 1; dr.candleTP1 = c; }
            if(dr.hitTP2 == 0 && lo  <= rangeLow  - distTP2) { dr.hitTP2 = 1; dr.candleTP2 = c; }
            if(dr.hitTP3 == 0 && lo  <= rangeLow  - distTP3) { dr.hitTP3 = 1; dr.candleTP3 = c; }
            if(dr.hitSL  == 0 && hi  >= rangeHigh)            { dr.hitSL  = 1; dr.candleSL  = c; }
         }
         else {
            // Aún sin breakout — trackear ambos lados
            double bullM = hi - rangeHigh;
            double bearM = rangeLow - lo;
            if(bullM > maxBullish) maxBullish = bullM;
            if(bearM > maxBearish) maxBearish = bearM;
         }
      }

      // Si nunca hubo breakout (brokeBull/brokeBear false)
      if(!brokeBull && !brokeBear) dr.breakoutDir = 0;

      // Máximo favorable / adverso
      dr.maxFavorable = (dr.breakoutDir == 1)  ? maxBullish :
                        (dr.breakoutDir == -1) ? maxBearish : 0;
      dr.maxAdverse   = (dr.breakoutDir == 1)  ? maxBearish :
                        (dr.breakoutDir == -1) ? maxBullish : 0;
      dr.closeNY      = lastClose;

      // ─ Reversión: terminó en el lado opuesto ─
      if(dr.breakoutDir == 1  && lastClose < rangeLow)  dr.reversedAfterBreak = 1;
      if(dr.breakoutDir == -1 && lastClose > rangeHigh) dr.reversedAfterBreak = 1;

      // ─ Retroceso % ─
      if(dr.maxFavorable > 0)
         dr.retracePct = NormalizeDouble(
            (dr.maxFavorable - (dr.breakoutDir == 1  ? (lastClose - rangeHigh) :
                                dr.breakoutDir == -1 ? (rangeLow - lastClose)  : 0))
            / dr.maxFavorable * 100.0, 1);

      // ─ PnL simulado ─
      // Modelo: entrada al primer breakout, SL = rango opuesto, TP3 = 3×rango
      // Risk = $100 fijo
      double lots = (rangeDist > 0) ? (SL_Reference_USD / (rangeDist * ContractSize_Ref)) : 0;
      lots = MathFloor(lots * 100) / 100.0; // redondear a 0.01
      if(lots < 0.01) lots = 0.01;
      double tickVal = ContractSize_Ref * _Point; // $/lot/point
      double vpp     = ContractSize_Ref;           // $/lot/price-unit

      // PnL con TP3 como objetivo (se cierra todo en TP3 o SL o SessionEnd)
      if(dr.hitTP3 && (!dr.hitSL || dr.candleTP3 < dr.candleSL))
         dr.pnlSimTP3 = lots * distTP3 * vpp;
      else if(dr.hitSL)
         dr.pnlSimTP3 = -lots * rangeDist * vpp;
      else // SessionEnd
         dr.pnlSimTP3 = lots * (dr.breakoutDir != 0 ? MathMax(0, dr.maxFavorable - dr.maxAdverse*0.3) : 0) * vpp;
      dr.pnlSimTP3 = NormalizeDouble(dr.pnlSimTP3, 2);

      // PnL con TP1
      if(dr.hitTP1 && (!dr.hitSL || dr.candleTP1 < dr.candleSL))
         dr.pnlSimTP1 = lots * distTP1 * vpp;
      else if(dr.hitSL)
         dr.pnlSimTP1 = -lots * rangeDist * vpp;
      else
         dr.pnlSimTP1 = lots * MathMax(0, dr.maxFavorable - dr.maxAdverse*0.3) * vpp;
      dr.pnlSimTP1 = NormalizeDouble(dr.pnlSimTP1, 2);

      // Guardar resultado
      if(resultCount < ArraySize(results)) {
         results[resultCount] = dr;
         resultCount++;
      }

      // Escribir fila al CSV
      WriteCSVRow(dr);
      barsProcessed++;
   }

   g_totalDays = resultCount;
   Print("Días procesados: ", g_totalDays);

   // ── RESUMEN ESTADÍSTICO ──────────────────────────────────────
   if(resultCount > 0)
   {
      ArrayResize(results, resultCount);
      PrintSummary(results, resultCount);
   }

   // Cerrar CSV
   FileClose(g_csvHandle);
   Print("✅ CSV generado: ", OutputFile);
   Print("   Ubicación: MQL5/Files/ (carpeta común de MT5)");
   Print("   O búscalo en: ", TerminalInfoString(TERMINAL_COMMONDATA_PATH), "\\Files\\");
}

//==================================================================
// ESCRIBIR CABECERA CSV
//==================================================================
void WriteCSVHeader()
{
   FileWrite(g_csvHandle,
      // Identificación
      "fecha",
      "dia_semana",          // Nombre del día
      "dia_num",             // 1=Lun, 2=Mar, 3=Mié, 4=Jue, 5=Vie

      // Rango pre-NY
      "range_pts",           // Rango en puntos de precio ($)
      "range_high",
      "range_low",
      "open_ny",             // Precio en apertura NY (14:50 UTC)

      // Breakout
      "breakout_dir",        // 1=alza, -1=baja, 0=no rompió
      "breakout_dir_str",    // "BUY" / "SELL" / "NONE"
      "breakout_vela",       // Vela M5 en que ocurrió (1=primera post-apertura)

      // Distancias TP (en puntos de precio = $)
      "dist_tp1",            // rangeDist × 1
      "dist_tp2",            // rangeDist × 2
      "dist_tp3",            // rangeDist × 3

      // Logros de TP (1=alcanzó, 0=no)
      "hit_tp1",
      "hit_tp2",
      "hit_tp3",
      "hit_sl",

      // Vela en que alcanzó (0 si no lo alcanzó)
      "vela_tp1",
      "vela_tp2",
      "vela_tp3",
      "vela_sl",

      // Movimientos máximos
      "max_favorable_pts",   // Máximo movimiento a favor del breakout
      "max_adverso_pts",     // Máximo movimiento en contra
      "max_fav_ratio",       // max_favorable / range (múltiplo del rango alcanzado)

      // Precio cierre sesión
      "close_ny",
      "move_neto_pts",       // close_ny vs openNY

      // Comportamiento post-breakout
      "retrace_pct",         // % de retroceso del pico favorable
      "reversed",            // 1 = terminó en el lado opuesto del breakout

      // Cuartil del rango (para análisis de rentabilidad por tamaño de rango)
      "range_quartile",      // Q1/Q2/Q3/Q4 (calculado post-hoc en Python/Excel)
      "range_bucket",        // Bucket de $2 en $2 (ej: "4-6", "6-8", etc.)

      // PnL simulado con $100 de riesgo
      "pnl_sim_tp3",         // Si TP3 como objetivo
      "pnl_sim_tp1",         // Si TP1 como objetivo

      // Estadístico para el análisis de factibilidad TP3
      "tp3_factible",        // 1 si max_favorable >= 3×range (sin importar si cerró bien)
      "tp3_neto",            // 1 si tp3_factible Y hit_sl=0 (no hubo SL antes del TP3)

      // Hora de breakout (para análisis de timing)
      "hora_breakout_utc"    // En formato HH:MM
   );
}

//==================================================================
// ESCRIBIR FILA CSV
//==================================================================
void WriteCSVRow(const DayResult &dr)
{
   string dayNames[] = {"Dom","Lun","Mar","Mié","Jue","Vie","Sáb"};
   int    dayNums[]  = {0,1,2,3,4,5,6}; // Lun=1...Vie=5

   string dirStr = (dr.breakoutDir == 1)  ? "BUY"  :
                   (dr.breakoutDir == -1) ? "SELL" : "NONE";

   // Día operativo (1=Lun...5=Vie)
   int dayOpNum = dr.weekday; // MT5: 1=Lun, 2=Mar, 3=Mié, 4=Jue, 5=Vie

   // Calcular hora del breakout en UTC
   // Apertura NY = 14:50 UTC, cada vela = 5 min
   string horaBreak = "N/A";
   if(dr.breakoutCandle > 0) {
      int minOffset = (dr.breakoutCandle - 1) * 5; // minutos desde 14:50
      int totalMin  = 14*60 + 50 + minOffset;
      int hh        = totalMin / 60;
      int mm        = totalMin % 60;
      horaBreak     = (hh < 10 ? "0" : "") + IntegerToString(hh) + ":" +
                      (mm < 10 ? "0" : "") + IntegerToString(mm);
   }

   // Bucket de rango (de $2 en $2)
   double r = dr.range;
   int    bucketLow = (int)(MathFloor(r / 2.0) * 2);
   string rangeBucket = IntegerToString(bucketLow) + "-" + IntegerToString(bucketLow + 2);

   // max_fav_ratio
   double maxFavRatio = (dr.range > 0) ? NormalizeDouble(dr.maxFavorable / dr.range, 3) : 0;

   // move_neto
   double moveNeto = NormalizeDouble(dr.closeNY - dr.openNY, 2);
   if(dr.breakoutDir == -1) moveNeto = -moveNeto; // en términos del breakout

   // tp3 factibilidad
   int tp3Factible = (dr.maxFavorable >= dr.range * 3.0) ? 1 : 0;
   int tp3Neto     = (tp3Factible == 1 && dr.hitSL == 0) ? 1 : 0;

   FileWrite(g_csvHandle,
      TimeToString(dr.date, TIME_DATE),
      dayNames[MathMin(dr.weekday, 6)],
      dayOpNum,
      DoubleToString(dr.range,    2),
      DoubleToString(dr.rangeHigh,2),
      DoubleToString(dr.rangeLow, 2),
      DoubleToString(dr.openNY,   2),
      IntegerToString(dr.breakoutDir),
      dirStr,
      IntegerToString(dr.breakoutCandle),
      DoubleToString(dr.distTP1,  2),
      DoubleToString(dr.distTP2,  2),
      DoubleToString(dr.distTP3,  2),
      IntegerToString(dr.hitTP1),
      IntegerToString(dr.hitTP2),
      IntegerToString(dr.hitTP3),
      IntegerToString(dr.hitSL),
      IntegerToString(dr.candleTP1),
      IntegerToString(dr.candleTP2),
      IntegerToString(dr.candleTP3),
      IntegerToString(dr.candleSL),
      DoubleToString(dr.maxFavorable, 2),
      DoubleToString(dr.maxAdverse,   2),
      DoubleToString(maxFavRatio,     3),
      DoubleToString(dr.closeNY,      2),
      DoubleToString(moveNeto,        2),
      DoubleToString(dr.retracePct,   1),
      IntegerToString(dr.reversedAfterBreak),
      "",                       // range_quartile (calculado en Python post-hoc)
      rangeBucket,
      DoubleToString(dr.pnlSimTP3, 2),
      DoubleToString(dr.pnlSimTP1, 2),
      IntegerToString(tp3Factible),
      IntegerToString(tp3Neto),
      horaBreak
   );
}

//==================================================================
// RESUMEN ESTADÍSTICO EN EL LOG DE MT5
//==================================================================
void PrintSummary(DayResult &r[], int n)
{
   Print("═══════════════════════════════════════════════════════");
   Print("  RESUMEN ESTADÍSTICO — ", n, " días analizados");
   Print("═══════════════════════════════════════════════════════");

   // ─ Rango ─
   double sumRange=0, minR=9999, maxR=0;
   for(int i=0;i<n;i++){
      sumRange += r[i].range;
      if(r[i].range < minR) minR = r[i].range;
      if(r[i].range > maxR) maxR = r[i].range;
   }
   Print("RANGO PRE-NY:");
   Print("  Media  : $", DoubleToString(sumRange/n, 2));
   Print("  Mínimo : $", DoubleToString(minR, 2));
   Print("  Máximo : $", DoubleToString(maxR, 2));

   // ─ Breakout ─
   int nBull=0, nBear=0, nNone=0;
   for(int i=0;i<n;i++){
      if(r[i].breakoutDir==1)  nBull++;
      else if(r[i].breakoutDir==-1) nBear++;
      else nNone++;
   }
   Print("DIRECCIÓN DEL BREAKOUT:");
   Print("  BUY  : ", nBull,  " (", DoubleToString(nBull*100.0/n,1),  "%)");
   Print("  SELL : ", nBear,  " (", DoubleToString(nBear*100.0/n,1),  "%)");
   Print("  NONE : ", nNone,  " (", DoubleToString(nNone*100.0/n,1),  "%)");

   // ─ Vela del breakout ─
   double sumCandle=0; int nCandle=0;
   int dist[27]; ArrayInitialize(dist,0);
   for(int i=0;i<n;i++){
      if(r[i].breakoutCandle > 0) {
         sumCandle += r[i].breakoutCandle;
         nCandle++;
         int c = MathMin(r[i].breakoutCandle, 26);
         dist[c]++;
      }
   }
   Print("VELA DEL BREAKOUT (M5 post-apertura):");
   Print("  Media  : vela ", DoubleToString(nCandle>0?sumCandle/nCandle:0, 1),
         " ≈ ", DoubleToString(nCandle>0?sumCandle/nCandle*5:0, 0), " min post-apertura");
   Print("  Distribución (top 10):");
   // Ordenar por frecuencia
   for(int c=1; c<=26; c++) {
      if(dist[c] > 0)
         Print("    Vela ", StringFormat("%2d",c), " (", StringFormat("%5s",TimeToString(0 + (14*60+50+(c-1)*5)*60, TIME_MINUTES)), " UTC): ",
               dist[c], " días (", DoubleToString(dist[c]*100.0/nCandle,1), "%)");
   }

   // ─ Hits de TP ─
   int nBreaks = nBull + nBear;
   int hTP1=0, hTP2=0, hTP3=0, hSL=0;
   for(int i=0;i<n;i++){
      if(r[i].breakoutDir==0) continue;
      hTP1 += r[i].hitTP1;
      hTP2 += r[i].hitTP2;
      hTP3 += r[i].hitTP3;
      hSL  += r[i].hitSL;
   }
   Print("HITS DE TP (sobre días con breakout, n=", nBreaks, "):");
   Print("  TP1 (1×rango): ", hTP1, " (", DoubleToString(hTP1*100.0/MathMax(nBreaks,1),1), "%)");
   Print("  TP2 (2×rango): ", hTP2, " (", DoubleToString(hTP2*100.0/MathMax(nBreaks,1),1), "%)");
   Print("  TP3 (3×rango): ", hTP3, " (", DoubleToString(hTP3*100.0/MathMax(nBreaks,1),1), "%)");
   Print("  SL  (revrs)  : ", hSL,  " (", DoubleToString(hSL*100.0/MathMax(nBreaks,1),1),  "%)");

   // ─ Factibilidad TP3 ─
   int nTP3f=0, nTP3n=0;
   for(int i=0;i<n;i++){
      if(r[i].maxFavorable >= r[i].range*3.0) nTP3f++;
      if(r[i].maxFavorable >= r[i].range*3.0 && r[i].hitSL==0) nTP3n++;
   }
   Print("FACTIBILIDAD TP3:");
   Print("  Precio alcanzó 3×rango     : ", nTP3f, " (", DoubleToString(nTP3f*100.0/n,1), "%)");
   Print("  Sin SL antes del TP3       : ", nTP3n, " (", DoubleToString(nTP3n*100.0/n,1), "%)");

   // ─ Velas promedio hasta TP1/2/3 ─
   double sumC1=0,sumC2=0,sumC3=0; int nC1=0,nC2=0,nC3=0;
   for(int i=0;i<n;i++){
      if(r[i].candleTP1>0){sumC1+=r[i].candleTP1;nC1++;}
      if(r[i].candleTP2>0){sumC2+=r[i].candleTP2;nC2++;}
      if(r[i].candleTP3>0){sumC3+=r[i].candleTP3;nC3++;}
   }
   Print("TIEMPO HASTA TP:");
   Print("  TP1: media vela ", DoubleToString(nC1>0?sumC1/nC1:0,1),
         " = ", DoubleToString(nC1>0?sumC1/nC1*5:0,0), " min");
   Print("  TP2: media vela ", DoubleToString(nC2>0?sumC2/nC2:0,1),
         " = ", DoubleToString(nC2>0?sumC2/nC2*5:0,0), " min");
   Print("  TP3: media vela ", DoubleToString(nC3>0?sumC3/nC3:0,1),
         " = ", DoubleToString(nC3>0?sumC3/nC3*5:0,0), " min");

   // ─ Reversiones ─
   int nRev=0;
   for(int i=0;i<n;i++) nRev += r[i].reversedAfterBreak;
   Print("REVERSIONES post-breakout: ", nRev, " (", DoubleToString(nRev*100.0/MathMax(nBreaks,1),1), "%)");

   // ─ Rendimiento por día de semana ─
   Print("RENDIMIENTO POR DÍA (TP3 como objetivo):");
   string dnames[] = {"","Lun","Mar","Mié","Jue","Vie"};
   for(int d=1;d<=5;d++){
      int nd=0,tp3d=0,sld=0; double netd=0;
      for(int i=0;i<n;i++){
         if(r[i].weekday != d) continue;
         if(r[i].breakoutDir==0) continue;
         nd++;
         if(r[i].hitTP3 && (!r[i].hitSL || r[i].candleTP3<r[i].candleSL)) tp3d++;
         if(r[i].hitSL) sld++;
         netd += r[i].pnlSimTP3;
      }
      if(nd>0)
         Print("  ", dnames[d], ": n=", nd, "  TP3%=", DoubleToString(tp3d*100.0/nd,1),
               "%  SL%=", DoubleToString(sld*100.0/nd,1), "%  Net=$", DoubleToString(netd,2));
   }

   // ─ Max favorable por bucket de rango ─
   Print("MAX FAVORABLE / RANGO por bucket:");
   double buckets_ratio_sum[]; ArrayResize(buckets_ratio_sum,10); ArrayInitialize(buckets_ratio_sum,0);
   int    buckets_count[]; ArrayResize(buckets_count,10); ArrayInitialize(buckets_count,0);
   for(int i=0;i<n;i++){
      if(r[i].range<=0 || r[i].breakoutDir==0) continue;
      int b=(int)(MathFloor(r[i].range/2.0)); // bucket 0=0-2, 1=2-4, ...
      if(b<10){
         buckets_ratio_sum[b] += r[i].maxFavorable/r[i].range;
         buckets_count[b]++;
      }
   }
   for(int b=0;b<10;b++){
      if(buckets_count[b]>0)
         Print("  Rango $",b*2,"-$",(b+1)*2,": n=",buckets_count[b],
               "  avg_fav_ratio=", DoubleToString(buckets_ratio_sum[b]/buckets_count[b],2), "×");
   }

   Print("═══════════════════════════════════════════════════════");
}

