//|         BreakoutNY_v8_FundingPips_XAUUSD.mq5                     |
//|   BreakoutNY v8.0 — FundingPips — XAUUSD (Gold Spot 100oz)       |
//|   Adapted from NDX100 version. Calibrate MinSL/MaxSL with        |
//|   BreakoutNY_Calibrator_XAUUSD.mq5 before backtesting.           |
//+------------------------------------------------------------------+
//
//  CONTRACT SPECS (FundingPips XAUUSD):
//    ContractSize  : 100 oz
//    TickSize      : 0.01
//    TickValue     : $1.00 / lot / tick  (100 oz × $0.01)
//    _Point        : 0.01
//    VolumeMin     : 0.01   VolumeMax: 5.00   VolumeStep: 0.01
//    ServerOffset  : UTC+2  (FundingPips standard)
//
//  LOT CALC SANITY CHECK (example):
//    slDistance    = 2.50  (raw price diff = $2.50 range)
//    valuePerPoint = TickValue / TickSize = 1.00 / 0.01 = 100
//    lotsRaw       = 100 / (2.50 × 100) = 0.40 lots
//    Verify risk   = 0.40 × 2.50 × 100 = $100.00 ✓
//
//  BUGS INHERITED FROM NDX100 — ALREADY FIXED (do NOT reintroduce):
//    [1] slDistance stored as raw price diff, compared to MinSL/MaxSL directly
//    [2] valuePerPoint = TickValue / TickSize (unified units)
//    [3] UseFixedLot removed — always dynamic
//    [4] No range-based for loops (MQL5 incompatible)
//    [5] Margin check via OrderCalcMargin before returning lots
//    [6] cachedLots calculated ONCE at range detection, not per tick
//    [7] ACCOUNT_MARGIN_FREE (not deprecated ACCOUNT_FREEMARGIN)
//    [8] FilterXxx: true=OPERA, false=SALTA; IsTradingDayAllowed() returns filter directly
//    [9] VPP via OrderCalcProfit (TickValue/TickSize inestable en backtester CFD XCCY)
//+------------------------------------------------------------------+
#property copyright   "BreakoutNY v8.0"
#property version     "8.02"
#property description "BreakoutNY NY Open Breakout — XAUUSD — FundingPips"
#property strict

#include <Trade\Trade.mqh>

//==================================================================
// INPUT PARAMETERS
//==================================================================

input group "=== HORARIO ==="
input int    ServerOffsetHours  = 2;      // Offset servidor vs UTC (FundingPips = UTC+2)
input int    EntryWindowEnd_Min = 15;     // Minutos del fin de ventana (14:50–15:HH UTC)

input group "=== RIESGO ==="
input double RiskAmountUSD      = 100.0;  // Riesgo fijo por operación en USD

input group "=== OBJETIVOS (Múltiplos del SL) ==="
input double TP1_RR             = 1.0;
input double TP2_RR             = 2.0;
input double TP3_RR             = 3.0;

input group "=== CIERRES PARCIALES ==="
input bool   EnablePartials     = false;
input int    TP1_ClosePct       = 40;     // % del lote a cerrar en TP1
input int    TP2_ClosePct       = 40;     // % del lote a cerrar en TP2

input group "=== BREAKEVEN ==="
input double BE_BufferPct       = 20.0;   // BE como % del SL (20% → BE cuando precio = entry + 0.20×SL)

input group "=== FILTROS ==="
input bool   FilterMonday       = true;   // true = OPERA el lunes
input bool   FilterTuesday      = true;
input bool   FilterWednesday    = true;
input bool   FilterThursday     = true;
input bool   FilterFriday       = true;
input double MinSL_Points       = 1.00;   // SL mínimo (puntos reales = precio raw) ← CALIBRAR
input double MaxSL_Points       = 5.00;   // SL máximo (puntos reales = precio raw) ← CALIBRAR
input bool   ConfirmOnClose     = true;   // SIEMPRE true — NO optimizar

input group "=== LOGGING ==="
input bool   EnableCSV          = true;

input group "=== VISUAL ==="
input bool   VIS_Enable         = true;

input group "=== CONFIG ==="
input int    MagicNumber        = 202402; // Único para XAUUSD

//==================================================================
// GLOBALES
//==================================================================

CTrade trade;

// Specs del símbolo (cargadas en OnInit)
double g_tickValue;
double g_tickSize;
double g_valuePerPoint;
double g_volumeMin;
double g_volumeMax;
double g_volumeStep;
int    g_digits;

// Estado diario
double   g_rangeHigh       = 0;
double   g_rangeLow        = 0;
double   g_slDistance      = 0;
double   g_cachedLots      = 0;
bool     g_rangeCalculated = false;   // Se intentó calcular (evita recalcular en cada tick)
bool     g_rangeSet        = false;   // Rango válido y dentro de filtros
bool     g_tradeExecuted   = false;
bool     g_be_activated    = false;
bool     g_tp1_hit         = false;
bool     g_tp2_hit         = false;
datetime g_lastDay         = 0;

// Estado ConfirmOnClose
bool     g_breakoutPending = false;
string   g_pendingDir      = "";
datetime g_pendingBarTime  = 0;

// Niveles del trade activo
double   g_entryPrice      = 0;
double   g_slLevel         = 0;
double   g_tpLevel1        = 0;
double   g_tpLevel2        = 0;
double   g_tpLevel3        = 0;
double   g_beLevel         = 0;
string   g_tradeDir        = "";
datetime g_tradeTime       = 0;

// CSV
int      g_csvHandle       = INVALID_HANDLE;

//==================================================================
// OnInit
//==================================================================
int OnInit()
{
   // --- Cargar specs del símbolo dinámicamente
   g_tickValue    = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   g_tickSize     = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   g_volumeMin    = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   g_volumeMax    = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   g_volumeStep   = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   g_digits       = (int)SymbolInfoInteger(_Symbol, SYMBOL_DIGITS);

   if(g_tickSize <= 0) {
      Print("CRITICAL ERROR: TickSize = 0. Verifique el símbolo.");
      return INIT_FAILED;
   }

   // ── BUG FIX [9]: ValuePerPoint robusto para XAUUSD CFD ───────────
   // PROBLEMA IDENTIFICADO (backtest 2021-2026):
   //   SymbolInfoDouble(SYMBOL_TRADE_TICK_VALUE) en el Strategy Tester
   //   reporta valores variables (~0.19–0.49) en lugar del correcto 1.00.
   //   Esto causa que el lotaje sea 2.6×–3.8× mayor de lo calculado,
   //   con pérdidas reales de $261–$384 por trade en vez de $100.
   //
   // SOLUCIÓN: usar OrderCalcProfit para medir el VPP real en vivo.
   //   Si 1 lot mueve $X por 1.0 punto de precio → VPP = X.
   //   Para XAUUSD (100 oz): 1 lot × $1/oz = $100 → VPP esperado = 100.
   //
   // FALLBACK: si OrderCalcProfit falla, usar ContractSize directamente
   //   (válido para instrumentos cotizados directamente en USD de cuenta).

   double ask0 = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double profitTest = 0;
   double contractSize = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_CONTRACT_SIZE);

   bool calcOK = OrderCalcProfit(ORDER_TYPE_BUY, _Symbol,
                                  1.0,           // 1 lote
                                  ask0,          // precio entrada
                                  ask0 + 1.0,    // precio salida = entry + 1.0 punto de precio
                                  profitTest);

   if(calcOK && profitTest > 0.01) {
      g_valuePerPoint = profitTest;   // $ reales por lote por 1.0 unidad de precio
      Print("VPP via OrderCalcProfit  : ", g_valuePerPoint,
            "  (esperado ~100 para XAUUSD 100oz)");
   }
   else {
      // Fallback: para instrumento cotizado en USD de cuenta, VPP = ContractSize
      g_valuePerPoint = contractSize;
      Print("VPP via ContractSize (fallback): ", g_valuePerPoint);
   }

   // Verificación cruzada con TickValue (solo informativa, NO se usa en el cálculo)
   double vppTickBased = (g_tickSize > 0) ? g_tickValue / g_tickSize : 0;
   Print("VPP via TickValue/TickSize (ref): ", vppTickBased,
         "  ← NO se usa (inestable en backtester CFD)");

   Print("╔══════════════════════════════════════════════════╗");
   Print("║  BreakoutNY v8.02 — XAUUSD — FundingPips        ║");
   Print("║  BUG FIX [9]: VPP via OrderCalcProfit           ║");
   Print("╚══════════════════════════════════════════════════╝");
   Print("── Symbol Specs ───────────────────────────────────");
   Print("  Símbolo       : ", _Symbol);
   Print("  ContractSize  : ", contractSize,   "  (esperado: 100)");
   Print("  TickValue     : ", g_tickValue,    "  (info; NO usado en lotcalc)");
   Print("  TickSize      : ", g_tickSize,     "  (esperado: 0.01)");
   Print("  ValuePerPoint : ", g_valuePerPoint,"  (esperado: 100.0) ← VPP CORREGIDO");
   Print("  _Point        : ", SymbolInfoDouble(_Symbol, SYMBOL_POINT), "  (esperado: 0.01)");
   Print("  VolumeMin     : ", g_volumeMin,    "  (esperado: 0.01)");
   Print("  VolumeMax     : ", g_volumeMax,    "  (esperado: 5.00)");
