   452	   if(OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots, askNow, marginRequired)) {
   453	      // BUG FIX [7]: ACCOUNT_MARGIN_FREE
   454	      double freeMargin = AccountInfoDouble(ACCOUNT_MARGIN_FREE);
   455	      if(marginRequired > freeMargin * 0.90) {
   456	         double safeMargin = freeMargin * 0.90;
