   bool inWindow = afterRangeCalc && beforeWindowEnd;

   if(!inWindow) return;

   // ── Gestión de posición abierta ───────────────────────────────
   if(HasOpenPosition()) {
      ManagePosition();
      return;
   }

   if(g_tradeExecuted) return;

   // ── PASO 2: Detección y confirmación del breakout ─────────────
   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);

   if(ConfirmOnClose) {
      datetime currentBarTime = iTime(_Symbol, PERIOD_M5, 0);

      // FASE A — Detección (primera vez que el precio cruza el rango)
      if(!g_breakoutPending) {
         if(ask > g_rangeHigh) {
            g_breakoutPending = true;
            g_pendingDir      = "buy";
            g_pendingBarTime  = currentBarTime;
            Print("Breakout detectado BUY en ", TimeToString(TimeCurrent()), " ask=", ask);
         }
         else if(bid < g_rangeLow) {
            g_breakoutPending = true;
            g_pendingDir      = "sell";
            g_pendingBarTime  = currentBarTime;
            Print("Breakout detectado SELL en ", TimeToString(TimeCurrent()), " bid=", bid);
         }
      }

      // FASE B — Confirmación (nueva vela M5 formada)
      if(g_breakoutPending && currentBarTime > g_pendingBarTime) {
         bool stillValid = (g_pendingDir == "buy"  && ask > g_rangeHigh) ||
                           (g_pendingDir == "sell" && bid < g_rangeLow);
         if(!stillValid) {
            Print("False breakout cancelado. Precio regresó al rango.");
            g_breakoutPending = false;
            g_pendingDir      = "";
            g_pendingBarTime  = 0;
         } else {
            ExecuteTrade(g_pendingDir);
         }
      }
   }
   else {
      // Sin confirmación: entrada en primer tick
      if(ask > g_rangeHigh)   ExecuteTrade("buy");
      else if(bid < g_rangeLow) ExecuteTrade("sell");
   }
}

