   247	double CalculateLotSize(double slPoints)
   248	{
   249	   //-------------------------------------------------------------------
   250	   // Funcion de lotaje robusta - compatible con todos los brokers,
   251	   // incluyendo aquellos que reportan TickValue=0 (ej. FundingPips NDX100)
   252	   //
   253	   // UNIDADES: slPoints = puntos REALES del índice (ej. 35.0 para un SL de 35 pts)
   254	   //           valuePerPoint = USD por lot por 1 punto real (ej. $20/lot/pt con ContractSize=20)
   255	   //           Lots = RiskUSD / (slPoints × valuePerPoint)
   256	   //           Ejemplo: $50 / (35 × $20) = 0.071 → 0.07 lots → riesgo real = 35×$20×0.07 = $49 ✅
   257	   //
   258	   // Cascada de fallback:
   259	   //   1. TickValue y TickSize validos  -> valuePerPoint = tv/ts
   260	   //   2. TickValue=0                  -> valuePerPoint = ContractSize (fallback)
   261	   //   3. Sin datos                    -> volumen minimo + log error
   262	   //-------------------------------------------------------------------
   263	   if(slPoints <= 0) return 0;
   264	
   265	   double tv  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   266	   double ts  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   267	   double cs  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_CONTRACT_SIZE);
   268	   double pt  = SymbolInfoDouble(_Symbol, SYMBOL_POINT);
   269	   double ls  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   270	   double mn  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   271	   double mx  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   272	
   273	   double valuePerPoint = 0;   // USD por lot por 1 punto de precio
   274	
   275	   // METODO 1: Broker reporta TickValue y TickSize correctos
   276	   if(tv > 0 && ts > 0)
   277	   {
   278	      valuePerPoint = tv / ts;
   279	   }
   280	   // METODO 2: TickValue=0 (bug en algunos brokers CFD)
   281	   // Para un CFD de índice: valuePerPoint = ContractSize
   282	   // Equivalencia: tv/ts = ContractSize×pt/pt = ContractSize
   283	   else if(cs > 0)
   284	   {
   285	      valuePerPoint = cs;
   286	      Print("INFO LotCalc: TickValue=0. Fallback: valuePerPoint=ContractSize=", cs);
   287	   }
   288	   else
   289	   {
   290	      Print("ERROR LotCalc: Datos insuficientes. TV=", tv, " TS=", ts,
   291	            " CS=", cs, " PT=", pt, ". Usando lote minimo.");
   292	      return mn;
   293	   }
   294	
   295	   if(valuePerPoint <= 0)
   296	   {
   297	      Print("ERROR LotCalc: valuePerPoint=0. Usando lote minimo.");
   298	      return mn;
   299	   }
   300	
   301	   // LOTAJE DINAMICO: Lots = RiskUSD / (SL_pts_reales × $/pt/lot)
   302	   double lotsRaw = RiskAmountUSD / (slPoints * valuePerPoint);
   303	   double lots    = MathFloor(lotsRaw / ls) * ls;
   304	   lots           = MathMax(mn, MathMin(mx, lots));
   305	
   306	   double realRisk = slPoints * valuePerPoint * lots;
   307	
   308	   // Guardar en variables globales para el CSV de diagnóstico
   309	   log_ValuePerPoint  = valuePerPoint;
   310	   log_RiskReal_USD   = realRisk;
   311	
   312	   // ── Verificación de margen disponible ────────────────────────
   313	   // Evita "not enough money" calculando el margen requerido
   314	   // y reduciendo lots hasta que quepan en el capital disponible.
   315	   double freeMargin  = AccountInfoDouble(ACCOUNT_MARGIN_FREE);
   316	   double marginPerLot = 0;
   317	   if(!OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, 1.0,
   318	                       SymbolInfoDouble(_Symbol, SYMBOL_ASK), marginPerLot))
   319	      marginPerLot = SymbolInfoDouble(_Symbol, SYMBOL_ASK) *
   320	                     SymbolInfoDouble(_Symbol, SYMBOL_TRADE_CONTRACT_SIZE) * 0.05;
   321	
   322	   if(marginPerLot > 0)
   323	   {
   324	      double maxLotsByMargin = MathFloor((freeMargin * 0.90) / marginPerLot / ls) * ls;
   325	      maxLotsByMargin = MathMax(mn, MathMin(mx, maxLotsByMargin));
   326	      if(lots > maxLotsByMargin)
   327	      {
   328	         Print("AVISO Margen: lots=", DoubleToString(lots,2),
   329	               " excede margen libre=$", DoubleToString(freeMargin,2),
   330	               " (max=", DoubleToString(maxLotsByMargin,2), " lots).",
   331	               " Reduciendo a ", DoubleToString(maxLotsByMargin,2));
   332	         lots = maxLotsByMargin;
   333	         realRisk = slPoints * valuePerPoint * lots;
   334	         log_RiskReal_USD = realRisk;
   335	      }
   336	   }
   337	
   338	   log_LotsCalculated = lotsRaw;
   339	
   340	   Print("LotCalc | SL=", DoubleToString(slPoints,2), "pts",
   341	         " | vpp=$", DoubleToString(valuePerPoint,2), "/pt/lot",
   342	         " | Raw=", DoubleToString(lotsRaw,4),
   343	         " | Lots=", DoubleToString(lots,2),
   344	         " | Risk=$", DoubleToString(realRisk,2),
   345	         " | Margin/lot=$", DoubleToString(marginPerLot,2),
   346	         " | FreeMargin=$", DoubleToString(freeMargin,2));
   347	
   348	   return lots;
