{
   if(!EnableCSV) return;
   string path = CSVFileName + ".csv";
   csvHandle = FileOpen(path, FILE_WRITE|FILE_CSV|FILE_ANSI|FILE_COMMON, ',');
   if(csvHandle == INVALID_HANDLE) { Print("ERROR CSV: ", GetLastError()); return; }
