1262	//+------------------------------------------------------------------+
1263	void CalcTrendFilter(double rangeMid)
1264	{
1265	   tf_midRange = rangeMid;
1266	
1267	   MqlRates R[];
1268	   int total = CopyRates(_Symbol, PERIOD_M5, 0, 600, R);
1269	   if(total < 10) { tf_prevClose = 0; tf_allowedDir = "both"; return; }
1270	   ArraySetAsSeries(R, true);
1271	
1272	   MqlDateTime nowUtc;
1273	   TimeToStruct(TimeCurrent() - (long)ServerOffsetHours * 3600, nowUtc);
1274	   int todayY = nowUtc.year, todayMo = nowUtc.mon, todayD = nowUtc.day;
1275	
1276	   double foundClose = 0;
1277	   datetime foundTime = 0;
1278	   for(int i = 0; i < total; i++)
1279	   {
1280	      MqlDateTime u;
1281	      TimeToStruct(R[i].time - (long)ServerOffsetHours * 3600, u);
1282	      if(u.year == todayY && u.mon == todayMo && u.day == todayD) continue;
1283	      int barMin = u.hour * 60 + u.min;
1284	      if(barMin <= 16 * 60 + 55) { foundClose = R[i].close; foundTime = R[i].time; break; }
1285	   }
1286	
1287	   if(foundClose <= 0) { tf_prevClose = 0; tf_allowedDir = "both";
1288	      Print("TF: No se encontró prevClose. Filtro no aplicado."); return; }
1289	
1290	   tf_prevClose  = foundClose;
1291	   double diff   = rangeMid - tf_prevClose;
1292	
1293	   if     (diff >  TF_Threshold_Pts) tf_allowedDir = "buy";
1294	   else if(diff < -TF_Threshold_Pts) tf_allowedDir = "sell";
1295	   else                               tf_allowedDir = TF_BlockNeutral ? "none" : "both";
1296	
1297	   Print("TF: prevClose=", DoubleToString(tf_prevClose,_Digits),
1298	         " mid=", DoubleToString(rangeMid,_Digits),
1299	         " diff=", DoubleToString(diff,2), "pts → dir=", tf_allowedDir);
1300	}
