{"language": "javascript", "code": "const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, BorderStyle, WidthType, ShadingType, VerticalAlign,
  PageBreak, LevelFormat
} = require('docx');
const fs = require('fs');

const bdr = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const bdrs = { top:bdr, bottom:bdr, left:bdr, right:bdr };
function cell(text, opts={}) {
  const { bold=false, bg="FFFFFF", align=AlignmentType.LEFT, color="000000", size=18, italic=false } = opts;
  return new TableCell({ borders:bdrs, shading:{fill:bg,type:ShadingType.CLEAR},
    margins:{top:80,bottom:80,left:120,right:120}, verticalAlign:VerticalAlign.CENTER,
    children:[new Paragraph({alignment:align,
      children:[new TextRun({text:String(text),bold,color,font:"Arial",size,italics:italic})]})]});
}
const hcell = (t,o={}) => cell(t,{bold:true,bg:"1F3864",color:"FFFFFF",...o});
const gcell = (t,o={}) => cell(t,{bg:"E2EFDA",color:"375623",bold:true,...o});
const rcell = (t,o={}) => cell(t,{bg:"FCE4D6",color:"9C0006",bold:true,...o});
const ycell = (t,o={}) => cell(t,{bg:"FFF2CC",color:"7F6000",bold:true,...o});
const bcell = (t,o={}) => cell(t,{bg:"DEEAF1",color:"1F497D",...o});
const wcell = (t,o={}) => cell(t,{bg:"F2F2F2",...o});
const gc2   = (t,o={}) => cell(t,{bg:"E2EFDA",color:"375623",...o});
const gold  = (t,o={}) => cell(t,{bg:"FFF8DC",color:"8B4513",bold:true,...o});

const h1 = t => new Paragraph({spacing:{before:360,after:120},
  children:[new TextRun({text:t,bold:true,size:30,color:"1F3864",font:"Arial"})]});
const h2 = t => new Paragraph({spacing:{before:240,after:80},
  children:[new TextRun({text:t,bold:true,size:22,color:"2E75B6",font:"Arial"})]});
const sp = () => new Paragraph({spacing:{before:60,after:60},children:[new TextRun("")]});
const hr = () => new Paragraph({border:{bottom:{style:BorderStyle.SINGLE,size:6,color:"2E75B6",space:1}},children:[new TextRun("")]});
function para(runs,opts={}) {
  if(typeof runs==='string') runs=[{text:runs}];
  return new Paragraph({spacing:{before:60,after:100},...opts,
    children:runs.map(r=>new TextRun({font:"Arial",size:20,...r}))});
}
const bul = (t,o={}) => new Paragraph({numbering:{reference:"bullets",level:0},spacing:{before:40,after:40},
  children:[new TextRun({text:t,font:"Arial",size:20,...o})]});
function alert(text,type="warn") {
  const cfg={crit:{bg:"FCE4D6",color:"9C0006",border:"C00000"},warn:{bg:"FFF2CC",color:"7F6000",border:"FF9900"},
    good:{bg:"E2EFDA",color:"375623",border:"70AD47"},info:{bg:"DEEAF1",color:"1F497D",border:"2E75B6"},
    gold:{bg:"FFF8DC",color:"8B4513",border:"DAA520"}};
  const c=cfg[type]||cfg.warn;
  return new Paragraph({spacing:{before:120,after:120},
    border:{left:{style:BorderStyle.THICK,size:20,color:c.border,space:8}},
    shading:{fill:c.bg,type:ShadingType.CLEAR}, indent:{left:360,right:200},
    children:[new TextRun({text,font:"Arial",size:20,color:c.color,bold:type==="crit"||type==="good"||type==="gold"})]});
}

